import type { Lang } from '@/lib/i18n/translations';

type ML = Record<Lang, string>;

export const MUSTALAH_CONTENT = {

  /* ── Page header ─────────────────────────────────────────── */
  'header.title': { en: `Mustalah al-Hadith`, ms: `Mustalah al-Hadith`, tur: `Mustalahu'l-Hadis`, urd: `مصطلح الحدیث`, ben: `মুসতালাহুল হাদিস`, fas: `مصطلح الحدیث`, zh: `圣训术语学（Mustalah al-Hadith）`, yue: `聖訓術語學（Mustalah al-Hadith）`, ja: `ムスタラフ・アル＝ハディース`, ru: `Мусталах аль-хадис`, es: `Mustalah al-Hadith`, ko: `무스탈라흐 알하디스`, ta: `முஸ்தலஹுல் ஹதீஸ்`, si: `මුස්තලහ් අල්-හදීස්` },
  'header.subtitle': { en: `The methodological science by which scholars verify whether a narration truly comes from the Prophet ﷺ`, ms: `Ilmu metodologi yang digunakan para ulama untuk mengesahkan sama ada sesuatu riwayat benar-benar datang daripada Nabi ﷺ`, tur: `Âlimlerin, bir rivayetin gerçekten Peygamber ﷺ'den gelip gelmediğini doğruladıkları metodolojik ilim`, urd: `وہ منہجی علم جس کے ذریعے علماء تصدیق کرتے ہیں کہ آیا کوئی روایت واقعی نبی ﷺ سے آئی ہے`, ben: `যে পদ্ধতিগত শাস্ত্রের মাধ্যমে আলেমগণ যাচাই করেন কোনো বর্ণনা সত্যিই নবী ﷺ থেকে এসেছে কিনা`, fas: `دانش روش‌مندی که علما با آن راستی‌آزمایی می‌کنند که آیا روایتی به‌راستی از پیامبر ﷺ است`, zh: `学者借以核实一段传述是否真正来自先知ﷺ的方法学`, yue: `學者藉以核實一段傳述是否真正嚟自先知ﷺ嘅方法學`, ja: `ある伝承が本当に預言者ﷺに由来するかを学者が検証するための方法論的学問`, ru: `Методологическая наука, с помощью которой учёные проверяют, действительно ли предание восходит к Пророку ﷺ`, es: `La ciencia metodológica con la que los sabios verifican si una narración procede verdaderamente del Profeta ﷺ`, ko: `어떤 전승이 진정으로 예언자 ﷺ로부터 온 것인지 학자들이 검증하는 방법론적 학문`, ta: `ஒரு அறிவிப்பு உண்மையில் நபி ﷺ அவர்களிடமிருந்து வந்ததா என்பதை அறிஞர்கள் சரிபார்க்கும் முறையியல் அறிவியல்`, si: `යම් වාර්තාවක් සැබැවින්ම නබි ﷺ තුමාගෙන් පැමිණියේද යන්න විද්වතුන් සත්‍යාපනය කරන ක්‍රමවේද විද්‍යාව` },

  /* ── The Science of Hadith ───────────────────────────────── */
  'whatis.heading': { en: `The Science of Hadith`, ms: `Ilmu Hadith`, tur: `Hadis İlmi`, urd: `علمِ حدیث`, ben: `হাদিস শাস্ত্র`, fas: `دانش حدیث`, zh: `圣训学`, yue: `聖訓學`, ja: `ハディース学`, ru: `Наука о хадисах`, es: `La ciencia del hadiz`, ko: `하디스 학`, ta: `ஹதீஸ் அறிவியல்`, si: `හදීස් විද්‍යාව` },
  'whatis.p1': { en: `A hadith (Arabic: الحديث, lit. "report" or "news") is a report of the words, actions, approvals, or physical descriptions of the Prophet Muhammad ﷺ. The Quran commands obedience to the Prophet ﷺ over 30 times, and the hadith corpus is the primary source through which that obedience is enacted after his death.`, ms: `Sebuah hadith (Arab: الحديث, harfiah "laporan" atau "berita") ialah laporan tentang kata-kata, perbuatan, perakuan, atau sifat fizikal Nabi Muhammad ﷺ. Al-Quran memerintahkan ketaatan kepada Nabi ﷺ lebih daripada 30 kali, dan himpunan hadith ialah sumber utama yang melaluinya ketaatan itu dilaksanakan selepas kewafatannya.`, tur: `Bir hadis (Arapça: الحديث, sözlükte "haber" ya da "rivayet"), Peygamber Muhammed ﷺ'in sözlerinin, fiillerinin, onaylarının ya da fiziksel niteliklerinin bir aktarımıdır. Kur'an, Peygamber ﷺ'e itaati otuzdan fazla yerde emreder ve hadis külliyatı, onun vefatından sonra bu itaatin gerçekleştirildiği başlıca kaynaktır.`, urd: `حدیث (عربی: الحديث، لغوی معنی "خبر" یا "اطلاع") نبی محمد ﷺ کے اقوال، افعال، تقریرات، یا جسمانی اوصاف کی روایت ہے۔ قرآن نبی ﷺ کی اطاعت کا حکم 30 سے زائد مرتبہ دیتا ہے، اور حدیث کا ذخیرہ وہ بنیادی ماخذ ہے جس کے ذریعے آپ کی وفات کے بعد اس اطاعت پر عمل ہوتا ہے۔`, ben: `হাদিস (আরবি: الحديث, আভিধানিক অর্থ "সংবাদ" বা "বার্তা") হলো নবী মুহাম্মদ ﷺ-এর কথা, কাজ, অনুমোদন, বা শারীরিক বর্ণনার বিবরণ। কুরআন নবী ﷺ-এর আনুগত্যের নির্দেশ ৩০ বারেরও বেশি দেয়, এবং হাদিস-সম্ভার সেই প্রাথমিক উৎস যার মাধ্যমে তাঁর ইন্তেকালের পর সেই আনুগত্য বাস্তবায়িত হয়।`, fas: `حدیث (عربی: الحديث، در لغت «خبر» یا «گزارش») گزارشی است از گفتار، کردار، تأییدها یا اوصاف ظاهری پیامبر محمد ﷺ. قرآن بیش از سی بار به اطاعت از پیامبر ﷺ فرمان می‌دهد و مجموعه‌ی حدیث، منبع اصلی‌ای است که این اطاعت پس از وفات او از طریق آن تحقق می‌یابد.`, zh: `圣训（阿拉伯语：الحديث，字面意为"报道"或"消息"）是对先知穆罕默德ﷺ言语、行为、默许或体貌的记述。《古兰经》三十多次命令顺从先知ﷺ，而圣训汇集是他归真之后践行这种顺从的首要来源。`, yue: `聖訓（阿拉伯語：الحديث，字面意為"報道"或"消息"）係對先知穆罕默德ﷺ言語、行為、默許或體貌嘅記述。《古蘭經》三十多次命令順從先知ﷺ，而聖訓匯集係佢歸真之後踐行呢種順從嘅首要來源。`, ja: `ハディース（アラビア語：الحديث、字義は「報せ」または「知らせ」）とは、預言者ムハンマドﷺの言葉・行い・黙認・身体的描写の伝えである。クルアーンは三十回以上にわたり預言者ﷺへの服従を命じており、ハディース集成は、彼の逝去の後にその服従が実践される第一の源である。`, ru: `Хадис (араб. الحديث, букв. «сообщение» или «весть»)  –  это сообщение о словах, действиях, одобрениях или внешнем облике Пророка Мухаммада ﷺ. Коран более тридцати раз повелевает повиноваться Пророку ﷺ, и свод хадисов  –  главный источник, через который это повиновение осуществляется после его кончины.`, es: `Un hadiz (árabe: الحديث, lit. "informe" o "noticia") es un relato de las palabras, acciones, aprobaciones o descripciones físicas del Profeta Muhammad ﷺ. El Corán ordena la obediencia al Profeta ﷺ más de 30 veces, y el corpus del hadiz es la fuente principal a través de la cual se cumple esa obediencia tras su muerte.`, ko: `하디스(아랍어: الحديث, 문자적으로 "보고" 또는 "소식")는 예언자 무함마드 ﷺ의 말씀, 행위, 승인, 또는 신체적 묘사에 대한 전언이다. 꾸란은 예언자 ﷺ에 대한 순종을 30회 넘게 명하며, 하디스 집성은 그분의 서거 이후 그 순종이 실행되는 일차적 원천이다.`, ta: `ஹதீஸ் (அரபி: الحديث, சொல்லர்த்தம் "செய்தி" அல்லது "தகவல்") என்பது நபி முஹம்மது ﷺ அவர்களின் சொற்கள், செயல்கள், ஒப்புதல்கள், அல்லது உடல் வர்ணனைகள் பற்றிய அறிக்கை. குர்ஆன் நபி ﷺ அவர்களுக்குக் கீழ்ப்படிய 30க்கும் மேற்பட்ட முறை கட்டளையிடுகிறது, மேலும் ஹதீஸ் தொகுப்பு அவர்களின் மறைவுக்குப் பின் அந்தக் கீழ்ப்படிதல் நிறைவேற்றப்படும் முதன்மை ஆதாரம்.`, si: `හදීසයක් (අරාබි: الحديث, වචනාර්ථයෙන් "වාර්තාව" හෝ "පුවත") යනු නබි මුහම්මද් ﷺ තුමාගේ වචන, ක්‍රියා, අනුමැතීන්, හෝ ශාරීරික විස්තර පිළිබඳ වාර්තාවකි. කුර්ආනය නබි ﷺ තුමාට කීකරු වීම 30 වතාවකට වැඩියෙන් අණ කරයි, තවද හදීස් එකතුව එතුමාගේ අභාවයෙන් පසු එම කීකරුකම ක්‍රියාත්මක වන ප්‍රධාන මූලාශ්‍රය වේ.` },
  'whatis.p2': { en: `Because the hadith directly governs Islamic law (fiqh), ritual, and theology, the question of authenticity is critical. Mustalah al-Hadith (lit. "the terminology of hadith") is the discipline that developed rigorous standards for evaluating every hadith: who narrated it, whether those narrators are trustworthy, whether the chain is unbroken, and whether the text (matn) is consistent with the Quran and stronger narrations.`, ms: `Oleh sebab hadith secara langsung mengatur hukum Islam (fiqh), ibadah, dan akidah, persoalan kesahihan adalah amat penting. Mustalah al-Hadith (harfiah "istilah hadith") ialah disiplin yang membangunkan piawaian ketat untuk menilai setiap hadith: siapa yang meriwayatkannya, sama ada para perawi itu boleh dipercayai, sama ada rangkaian sanad tidak terputus, dan sama ada teks (matan) selaras dengan al-Quran dan riwayat yang lebih kuat.`, tur: `Hadis, İslam hukukunu (fıkıh), ibadeti ve akideyi doğrudan belirlediği için sıhhat meselesi çok önemlidir. Mustalahu'l-Hadis (sözlükte "hadis ıstılahı"), her hadisi değerlendirmek için titiz ölçütler geliştiren ilim dalıdır: onu kim rivayet etti, bu râviler güvenilir mi, isnad kesintisiz mi ve metin (metn) Kur'an'a ve daha güçlü rivayetlere uygun mu.`, urd: `چونکہ حدیث براہِ راست اسلامی قانون (فقہ)، عبادات، اور عقیدہ کو منضبط کرتی ہے، اس لیے صحت کا سوال نہایت اہم ہے۔ مصطلح الحدیث (لغوی معنی "حدیث کی اصطلاحات") وہ علم ہے جس نے ہر حدیث کو پرکھنے کے لیے سخت معیار وضع کیے: اسے کس نے روایت کیا، آیا وہ راوی قابلِ اعتماد ہیں، آیا سند متصل ہے، اور آیا متن قرآن اور قوی تر روایات سے ہم آہنگ ہے۔`, ben: `যেহেতু হাদিস সরাসরি ইসলামি আইন (ফিকহ), ইবাদত ও আকিদা নিয়ন্ত্রণ করে, তাই সত্যতার প্রশ্নটি অত্যন্ত গুরুত্বপূর্ণ। মুসতালাহুল হাদিস (আভিধানিক অর্থ "হাদিসের পরিভাষা") হলো সেই শাস্ত্র যা প্রতিটি হাদিস মূল্যায়নের জন্য কঠোর মানদণ্ড গড়ে তুলেছে: কে এটি বর্ণনা করেছে, সেই বর্ণনাকারীরা নির্ভরযোগ্য কিনা, সনদ অবিচ্ছিন্ন কিনা, এবং মতন (পাঠ) কুরআন ও অধিকতর শক্তিশালী বর্ণনার সাথে সামঞ্জস্যপূর্ণ কিনা।`, fas: `از آنجا که حدیث به‌طور مستقیم فقه، عبادت و عقیده‌ی اسلامی را تنظیم می‌کند، مسئله‌ی صحت بسیار حیاتی است. مصطلح الحدیث (در لغت «اصطلاحات حدیث») دانشی است که برای ارزیابی هر حدیث معیارهای سخت‌گیرانه پدید آورد: چه کسی آن را روایت کرد، آیا آن راویان مورد اعتمادند، آیا سند پیوسته است، و آیا متن با قرآن و روایات قوی‌تر سازگار است.`, zh: `由于圣训直接规范伊斯兰教法（菲格亥）、功修与信仰，真伪问题至关重要。圣训术语学（字面意为"圣训的术语"）是为评估每段圣训而制定严格标准的学科：谁传述了它、那些传述者是否可信、传述链是否连贯、以及经文（正文）是否与《古兰经》及更强的传述一致。`, yue: `由於聖訓直接規範伊斯蘭教法（菲格亥）、功修同信仰，真偽問題至關重要。聖訓術語學（字面意為"聖訓嘅術語"）係為評估每段聖訓而制定嚴格標準嘅學科：邊個傳述咗佢、嗰啲傳述者是否可信、傳述鏈是否連貫、以及經文（正文）是否與《古蘭經》及更強嘅傳述一致。`, ja: `ハディースはイスラム法（フィクフ）・儀礼・神学を直接規定するため、真正性の問題はきわめて重要である。ムスタラフ・アル＝ハディース（字義は「ハディースの術語」）は、あらゆるハディースを評価するための厳格な基準を発展させた学問である。誰がそれを伝えたか、その伝承者たちは信頼できるか、連鎖は途切れていないか、そして本文（マトン）がクルアーンやより強い伝承と矛盾していないか。`, ru: `Поскольку хадис непосредственно определяет исламское право (фикх), обряд и вероучение, вопрос достоверности критически важен. Мусталах аль-хадис (букв. «терминология хадиса»)  –  дисциплина, выработавшая строгие критерии оценки каждого хадиса: кто его передал, надёжны ли эти передатчики, не прервана ли цепь и согласуется ли текст (матн) с Кораном и более сильными преданиями.`, es: `Dado que el hadiz rige directamente la ley islámica (fiqh), el rito y la teología, la cuestión de la autenticidad es crucial. El Mustalah al-Hadith (lit. "la terminología del hadiz") es la disciplina que desarrolló criterios rigurosos para evaluar cada hadiz: quién lo narró, si esos narradores son fiables, si la cadena es ininterrumpida y si el texto (matn) es coherente con el Corán y con narraciones más fuertes.`, ko: `하디스는 이슬람법(피크흐), 의례, 신학을 직접 규율하므로 진위 문제가 결정적이다. 무스탈라흐 알하디스(문자적으로 "하디스의 용어")는 모든 하디스를 평가하기 위한 엄격한 기준을 발전시킨 학문이다: 누가 그것을 전했는가, 그 전승자들이 신뢰할 만한가, 전승 사슬이 끊기지 않았는가, 그리고 본문(마튼)이 꾸란 및 더 강한 전승과 일치하는가.`, ta: `ஹதீஸ் இஸ்லாமிய சட்டத்தை (ஃபிக்ஹ்), வழிபாட்டை, இறையியலை நேரடியாக ஆளுவதால், சரித்தன்மை குறித்த கேள்வி மிக முக்கியமானது. முஸ்தலஹுல் ஹதீஸ் (சொல்லர்த்தம் "ஹதீஸின் கலைச்சொற்கள்") ஒவ்வொரு ஹதீஸையும் மதிப்பிடுவதற்கு கடுமையான தரநிலைகளை உருவாக்கிய துறை: அதை யார் அறிவித்தார், அந்த அறிவிப்பாளர்கள் நம்பகமானவர்களா, சங்கிலி அறுபடாமல் உள்ளதா, மற்றும் உரை (மத்ன்) குர்ஆனுடனும் வலுவான அறிவிப்புகளுடனும் ஒத்துப்போகிறதா.`, si: `හදීසය ඉස්ලාමීය නීතිය (ෆික්හ්), චාරිත්‍ර, සහ දේවධර්මය සෘජුව පාලනය කරන බැවින්, සත්‍යතාව පිළිබඳ ප්‍රශ්නය ඉතා තීරණාත්මකය. මුස්තලහ් අල්-හදීස් (වචනාර්ථයෙන් "හදීසයේ පාරිභාෂිකය") යනු සෑම හදීසයක්ම ඇගයීමට දැඩි ප්‍රමිතීන් වර්ධනය කළ විෂයයි: එය වාර්තා කළේ කවුද, එම වාර්තාකරුවන් විශ්වාසනීයද, දාමය නොකැඩී ඇද්ද, සහ පාඨය (මත්න්) කුර්ආනය හා වඩා ශක්තිමත් වාර්තා සමඟ එකඟද.` },
  'whatis.hadith.translation': { en: `"Whoever deliberately lies about me  –  let him take his seat in the Fire." (Bukhari 110, Muslim 4)`, ms: `"Sesiapa yang berdusta atasku dengan sengaja  –  hendaklah dia menyediakan tempat duduknya dalam Neraka." (Bukhari 110, Muslim 4)`, tur: `"Kim bana bilerek yalan isnat ederse  –  cehennemdeki yerine hazırlansın." (Buhârî 110, Müslim 4)`, urd: `"جس نے جان بوجھ کر مجھ پر جھوٹ باندھا  –  وہ اپنا ٹھکانا جہنم میں بنا لے۔" (بخاری ۱۱۰، مسلم ۴)`, ben: `"যে ইচ্ছাকৃতভাবে আমার নামে মিথ্যা বলে  –  সে যেন জাহান্নামে তার আসন গ্রহণ করে।" (বুখারি ১১০, মুসলিম ৪)`, fas: `"هرکس عمداً بر من دروغ ببندد  –  جایگاه خود را در آتش آماده کند." (بخاری ۱۱۰، مسلم ۴)`, zh: `"谁故意假借我之名撒谎  –  让他在火狱中自备座位。"（布哈里110，穆斯林4）`, yue: `"邊個故意假借我之名撒謊  –  就讓佢喺火獄中自備座位。"（布哈里110，穆斯林4）`, ja: `「故意に私について偽る者は  –  火獄に自らの座を占めるがよい。」（ブハーリー110、ムスリム4）`, ru: `"Кто намеренно лжёт на меня  –  пусть займёт своё место в Огне." (Бухари 110, Муслим 4)`, es: `"Quien mienta sobre mí deliberadamente  –  que tome su asiento en el Fuego." (Bukhari 110, Muslim 4)`, ko: `"고의로 나에 대해 거짓말하는 자는  –  불지옥에 자기 자리를 잡게 하라." (부카리 110, 무슬림 4)`, ta: `"என் மீது வேண்டுமென்றே பொய் சொல்பவர்  –  நரகத்தில் தம் இருக்கையை அமைத்துக்கொள்ளட்டும்." (புகாரி 110, முஸ்லிம் 4)`, si: `"මා ගැන හිතාමතාම බොරු කියන්නා  –  නිරයේ තම අසුන සූදානම් කරගනීවා." (බුහාරි 110, මුස්ලිම් 4)` },
  'whatis.hadith.note': { en: `This hadith, narrated by over 80 Companions, is the driving motivation behind the entire science of hadith criticism  –  to protect the Prophet's ﷺ legacy from fabrication.`, ms: `Hadith ini, yang diriwayatkan oleh lebih 80 Sahabat, adalah dorongan utama di sebalik keseluruhan ilmu kritik hadith  –  untuk melindungi warisan Nabi ﷺ daripada pemalsuan.`, tur: `Seksenden fazla sahabe tarafından rivayet edilen bu hadis, bütün hadis tenkidi ilminin ardındaki itici güçtür  –  Peygamber ﷺ'in mirasını uydurmadan korumak için.`, urd: `یہ حدیث، جسے 80 سے زائد صحابہ نے روایت کیا، پورے علمِ نقدِ حدیث کے پیچھے بنیادی محرک ہے  –  تاکہ نبی ﷺ کی میراث کو وضع و افترا سے محفوظ رکھا جائے۔`, ben: `এই হাদিস, যা ৮০-এর অধিক সাহাবি বর্ণনা করেছেন, সমগ্র হাদিস-সমালোচনা শাস্ত্রের পেছনে চালিকাশক্তি  –  নবী ﷺ-এর উত্তরাধিকারকে জালিয়াতি থেকে রক্ষা করতে।`, fas: `این حدیث که بیش از هشتاد صحابی آن را روایت کرده‌اند، انگیزه‌ی محرک تمام دانش نقد حدیث است  –  برای پاسداری از میراث پیامبر ﷺ در برابر جعل.`, zh: `这段由八十多位圣门弟子传述的圣训，是整个圣训批判学背后的推动力  –  为保护先知ﷺ的遗产免遭伪造。`, yue: `呢段由八十多位聖門弟子傳述嘅聖訓，係整個聖訓批判學背後嘅推動力  –  為保護先知ﷺ嘅遺產免遭偽造。`, ja: `八十名を超える教友によって伝えられたこのハディースは、ハディース批判学全体の原動力である  –  預言者ﷺの遺産を捏造から守るために。`, ru: `Этот хадис, переданный более чем восемьюдесятью сподвижниками,  –  движущая сила всей науки критики хадиса  –  чтобы защитить наследие Пророка ﷺ от подлога.`, es: `Este hadiz, narrado por más de 80 Compañeros, es la motivación impulsora de toda la ciencia de la crítica del hadiz  –  para proteger el legado del Profeta ﷺ de la falsificación.`, ko: `80명이 넘는 교우들이 전한 이 하디스는 하디스 비평학 전체의 원동력이다  –  예언자 ﷺ의 유산을 위조로부터 보호하기 위함이다.`, ta: `80க்கும் மேற்பட்ட தோழர்களால் அறிவிக்கப்பட்ட இந்த ஹதீஸ், முழு ஹதீஸ் விமர்சன அறிவியலுக்குப் பின்னால் உள்ள உந்து சக்தி  –  நபி ﷺ அவர்களின் மரபை இட்டுக்கட்டுதலிலிருந்து பாதுகாக்க.`, si: `සහාබාවරුන් 80කට වැඩි පිරිසක් වාර්තා කළ මෙම හදීසය, මුළු හදීස් විවේචන විද්‍යාවටම පිටුපසින් ඇති ගාමක බලවේගයයි  –  නබි ﷺ තුමාගේ උරුමය ව්‍යාජ නිර්මාණයෙන් ආරක්ෂා කිරීමට.` },

  /* ── Structure: Isnad and Matn ───────────────────────────── */
  'structure.heading': { en: `Structure of a Hadith: Isnad and Matn`, ms: `Struktur Hadith: Isnad dan Matan`, tur: `Bir Hadisin Yapısı: İsnad ve Metin`, urd: `حدیث کی ساخت: اسناد اور متن`, ben: `হাদিসের গঠন: ইসনাদ ও মতন`, fas: `ساختار حدیث: اسناد و متن`, zh: `圣训的结构：传述链与正文`, yue: `聖訓嘅結構：傳述鏈與正文`, ja: `ハディースの構造：イスナードとマトン`, ru: `Структура хадиса: иснад и матн`, es: `La estructura de un hadiz: isnad y matn`, ko: `하디스의 구조: 이스나드와 마튼`, ta: `ஹதீஸின் அமைப்பு: இஸ்னாத் மற்றும் மத்ன்`, si: `හදීසයක ව්‍යුහය: ඉස්නාද් සහ මත්න්` },
  'structure.isnad.heading': { en: `Isnad (Chain of Narrators)`, ms: `Isnad (Rangkaian Perawi)`, tur: `İsnad (Râvîler Zinciri)`, urd: `اسناد (راویوں کا سلسلہ)`, ben: `ইসনাদ (বর্ণনাকারীদের শৃঙ্খল)`, fas: `اسناد (زنجیره‌ی راویان)`, zh: `传述链（伊斯纳德）`, yue: `傳述鏈（伊斯納德）`, ja: `イスナード（伝承者の連鎖）`, ru: `Иснад (цепь передатчиков)`, es: `Isnad (cadena de narradores)`, ko: `이스나드 (전승자의 사슬)`, ta: `இஸ்னாத் (அறிவிப்பாளர் சங்கிலி)`, si: `ඉස්නාද් (වාර්තාකරුවන්ගේ දාමය)` },
  'structure.isnad.body': { en: `The sequence of narrators through which the hadith was transmitted from the Prophet ﷺ. A typical isnad reads: "A told us, from B, from C, from D (a Companion), that the Prophet ﷺ said..." The isnad is the cornerstone of hadith authentication  –  it is what distinguishes Islamic hadith criticism from all other ancient historical traditions.`, ms: `Urutan perawi yang melaluinya hadith disampaikan daripada Nabi ﷺ. Isnad yang lazim berbunyi: "A memberitahu kami, daripada B, daripada C, daripada D (seorang Sahabat), bahawa Nabi ﷺ bersabda..." Isnad ialah tonggak pengesahan hadith  –  ia yang membezakan kritik hadith Islam daripada semua tradisi sejarah purba yang lain.`, tur: `Hadisin Peygamber ﷺ'den aktarıldığı râvîler dizisi. Tipik bir isnad şöyledir: "A bize haber verdi, B'den, C'den, D'den (bir sahabe) ki Peygamber ﷺ şöyle buyurdu..." İsnad, hadis sıhhatinin temel taşıdır  –  İslam hadis tenkidini diğer bütün eski tarih geleneklerinden ayıran şeydir.`, urd: `راویوں کا وہ تسلسل جس کے ذریعے حدیث نبی ﷺ سے منتقل ہوئی۔ ایک عام اسناد یوں ہوتی ہے: "ہمیں الف نے بتایا، ب سے، ج سے، د سے (ایک صحابی)، کہ نبی ﷺ نے فرمایا..." اسناد حدیث کی تصدیق کا سنگِ بنیاد ہے  –  یہی وہ چیز ہے جو اسلامی نقدِ حدیث کو دیگر تمام قدیم تاریخی روایات سے ممتاز کرتی ہے۔`, ben: `যে ধারাবাহিক বর্ণনাকারীদের মধ্য দিয়ে হাদিস নবী ﷺ থেকে সঞ্চারিত হয়েছে। একটি সাধারণ ইসনাদ এমন: "ক আমাদের জানিয়েছেন, খ থেকে, গ থেকে, ঘ (একজন সাহাবি) থেকে, যে নবী ﷺ বলেছেন..." ইসনাদ হাদিস সত্যায়নের ভিত্তিপ্রস্তর  –  এটিই ইসলামি হাদিস-সমালোচনাকে অন্য সকল প্রাচীন ঐতিহাসিক ঐতিহ্য থেকে পৃথক করে।`, fas: `زنجیره‌ی راویانی که حدیث از طریق آنان از پیامبر ﷺ نقل شده است. اسنادی معمول چنین است: «الف به ما خبر داد، از ب، از ج، از د (یکی از صحابه)، که پیامبر ﷺ فرمود...» اسناد سنگ‌بنای اعتبارسنجی حدیث است  –  همان چیزی که نقد حدیث اسلامی را از همه‌ی سنت‌های تاریخی کهن دیگر متمایز می‌کند.`, zh: `圣训自先知ﷺ传下来所经过的传述者次序。典型的传述链是："甲告诉我们，传自乙，传自丙，传自丁（一位圣门弟子），先知ﷺ说……"传述链是圣训鉴定的基石  –  正是它使伊斯兰的圣训批判有别于其他一切古代史学传统。`, yue: `聖訓自先知ﷺ傳落嚟所經過嘅傳述者次序。典型嘅傳述鏈係："甲話畀我哋知，傳自乙，傳自丙，傳自丁（一位聖門弟子），先知ﷺ話……"傳述鏈係聖訓鑑定嘅基石  –  正係佢使伊斯蘭嘅聖訓批判有別於其他一切古代史學傳統。`, ja: `ハディースが預言者ﷺから伝えられた伝承者の順序。典型的なイスナードはこうである。「甲がわれわれに告げた、乙から、丙から、丁（ある教友）から、預言者ﷺが仰せられた……」イスナードはハディース真正化の礎であり  –  イスラムのハディース批判を他のあらゆる古代の史学伝統と分かつものである。`, ru: `Последовательность передатчиков, через которых хадис дошёл от Пророка ﷺ. Типичный иснад звучит так: «А сообщил нам, от Б, от В, от Г (сподвижника), что Пророк ﷺ сказал...» Иснад  –  краеугольный камень удостоверения хадиса  –  именно он отличает исламскую критику хадиса от всех прочих древних исторических традиций.`, es: `La secuencia de narradores a través de los cuales se transmitió el hadiz desde el Profeta ﷺ. Un isnad típico dice: "A nos contó, de B, de C, de D (un Compañero), que el Profeta ﷺ dijo..." El isnad es la piedra angular de la autenticación del hadiz  –  es lo que distingue la crítica islámica del hadiz de todas las demás tradiciones históricas antiguas.`, ko: `하디스가 예언자 ﷺ로부터 전해진 전승자들의 순서. 전형적인 이스나드는 이렇다: "갑이 우리에게 전하기를, 을에게서, 병에게서, 정(한 교우)에게서, 예언자 ﷺ께서 말씀하시기를..." 이스나드는 하디스 인증의 초석이며  –  이슬람의 하디스 비평을 다른 모든 고대 역사 전통과 구별 짓는 것이다.`, ta: `ஹதீஸ் நபி ﷺ அவர்களிடமிருந்து கடத்தப்பட்ட அறிவிப்பாளர்களின் வரிசை. ஒரு வழக்கமான இஸ்னாத் இப்படி இருக்கும்: "அ எங்களுக்குக் கூறினார், ஆ-விடமிருந்து, இ-விடமிருந்து, ஈ (ஒரு தோழர்)-விடமிருந்து, நபி ﷺ கூறினார்கள்..." இஸ்னாத் ஹதீஸ் சரிபார்ப்பின் அடிக்கல்  –  இஸ்லாமிய ஹதீஸ் விமர்சனத்தை மற்ற எல்லா பண்டைய வரலாற்று மரபுகளிலிருந்தும் வேறுபடுத்துவது இதுவே.`, si: `හදීසය නබි ﷺ තුමාගෙන් සම්ප්‍රේෂණය වූ වාර්තාකරුවන්ගේ අනුක්‍රමය. සාමාන්‍ය ඉස්නාද් එකක් මෙසේය: "අ අපට දැන්වීය, බ ගෙන්, ක ගෙන්, ඩ (සහාබාවරයෙකු) ගෙන්, නබි ﷺ තුමා මෙසේ වදාළ බව..." ඉස්නාද් යනු හදීස් සත්‍යාපනයේ මූලික ගල  –  ඉස්ලාමීය හදීස් විවේචනය අන් සියලු පුරාණ ඓතිහාසික සම්ප්‍රදායන්ගෙන් වෙන් කරන්නේ එයයි.` },
  'structure.matn.heading': { en: `Matn (Text)`, ms: `Matan (Teks)`, tur: `Metin (Metn)`, urd: `متن (عبارت)`, ben: `মতন (পাঠ)`, fas: `متن (نص)`, zh: `正文（马汤）`, yue: `正文（馬湯）`, ja: `マトン（本文）`, ru: `Матн (текст)`, es: `Matn (texto)`, ko: `마튼 (본문)`, ta: `மத்ன் (உரை)`, si: `මත්න් (පාඨය)` },
  'structure.matn.body': { en: `The actual content of the hadith  –  what the Prophet ﷺ said, did, or approved. The matn is evaluated against: (1) the Quran, (2) other mutawatir (mass-transmitted) hadiths, (3) established principles of Islamic law, and (4) historical reality. A text that contradicts these is suspect even with a sound isnad.`, ms: `Kandungan sebenar hadith  –  apa yang Nabi ﷺ katakan, lakukan, atau perakui. Matan dinilai berdasarkan: (1) al-Quran, (2) hadith mutawatir (yang diriwayatkan secara beramai-ramai) lain, (3) prinsip-prinsip hukum Islam yang mapan, dan (4) realiti sejarah. Teks yang bertentangan dengan ini diragui walaupun isnadnya sahih.`, tur: `Hadisin asıl içeriği  –  Peygamber ﷺ'in söylediği, yaptığı ya da onayladığı şey. Metin şunlara göre değerlendirilir: (1) Kur'an, (2) diğer mütevatir (yaygın olarak nakledilen) hadisler, (3) yerleşik İslam hukuku ilkeleri ve (4) tarihsel gerçeklik. Bunlara aykırı bir metin, isnadı sağlam olsa bile şüphelidir.`, urd: `حدیث کا اصل مواد  –  جو نبی ﷺ نے کہا، کیا، یا برقرار رکھا۔ متن کو ان کے مقابل پرکھا جاتا ہے: (1) قرآن، (2) دیگر متواتر (کثرت سے نقل کردہ) احادیث، (3) اسلامی قانون کے مستحکم اصول، اور (4) تاریخی حقیقت۔ ایسا متن جو ان کے خلاف ہو، اسناد صحیح ہونے کے باوجود مشکوک ہے۔`, ben: `হাদিসের প্রকৃত বিষয়বস্তু  –  নবী ﷺ যা বলেছেন, করেছেন, বা অনুমোদন করেছেন। মতন যাচাই করা হয়: (1) কুরআন, (2) অন্যান্য মুতাওয়াতির (ব্যাপকভাবে বর্ণিত) হাদিস, (3) ইসলামি আইনের প্রতিষ্ঠিত নীতি, এবং (4) ঐতিহাসিক বাস্তবতার বিপরীতে। এসবের বিরোধী পাঠ, সনদ সহিহ হলেও সন্দেহজনক।`, fas: `محتوای واقعی حدیث  –  آنچه پیامبر ﷺ گفت، کرد یا تأیید کرد. متن در برابر این‌ها سنجیده می‌شود: (۱) قرآن، (۲) دیگر احادیث متواتر (که به‌طور گسترده نقل شده‌اند)، (۳) اصول جاافتاده‌ی فقه اسلامی، و (۴) واقعیت تاریخی. متنی که با این‌ها در تضاد باشد، حتی با اسناد درست، مشکوک است.`, zh: `圣训的实际内容  –  先知ﷺ所说、所行或所默许者。正文需对照以下检验：（1）《古兰经》，（2）其他多人传述（连续传述）的圣训，（3）确立的伊斯兰教法原则，（4）历史事实。与这些相抵触的正文，纵有可靠传述链亦属可疑。`, yue: `聖訓嘅實際內容  –  先知ﷺ所講、所行或所默許者。正文需對照以下檢驗：（1）《古蘭經》，（2）其他多人傳述（連續傳述）嘅聖訓，（3）確立嘅伊斯蘭教法原則，（4）歷史事實。與呢啲相抵觸嘅正文，縱有可靠傳述鏈亦屬可疑。`, ja: `ハディースの実際の内容  –  預言者ﷺが言い、行い、または認めたこと。本文は次に照らして評価される。(1) クルアーン、(2) 他のムタワーティル（大量に伝えられた）ハディース、(3) 確立されたイスラム法の原則、(4) 歴史的事実。これらに矛盾する本文は、たとえイスナードが健全でも疑わしい。`, ru: `Собственно содержание хадиса  –  что Пророк ﷺ сказал, сделал или одобрил. Матн оценивается по: (1) Корану, (2) другим мутаватир (массово переданным) хадисам, (3) устоявшимся принципам исламского права и (4) исторической действительности. Текст, противоречащий им, сомнителен даже при надёжном иснаде.`, es: `El contenido real del hadiz  –  lo que el Profeta ﷺ dijo, hizo o aprobó. El matn se evalúa frente a: (1) el Corán, (2) otros hadices mutawatir (transmitidos masivamente), (3) los principios establecidos de la ley islámica y (4) la realidad histórica. Un texto que los contradice es sospechoso aun con un isnad sólido.`, ko: `하디스의 실제 내용  –  예언자 ﷺ께서 말씀하시거나 행하시거나 승인하신 것. 마튼은 다음에 비추어 평가된다: (1) 꾸란, (2) 다른 무타와티르(대량 전승) 하디스, (3) 확립된 이슬람법 원칙, (4) 역사적 사실. 이것들과 모순되는 본문은 이스나드가 건전해도 의심스럽다.`, ta: `ஹதீஸின் உண்மையான உள்ளடக்கம்  –  நபி ﷺ கூறிய, செய்த, அல்லது ஒப்புதலளித்தது. மத்ன் இவற்றுக்கு எதிராக மதிப்பிடப்படுகிறது: (1) குர்ஆன், (2) பிற முதவாத்திர் (பெருந்திரளாக அறிவிக்கப்பட்ட) ஹதீஸ்கள், (3) நிறுவப்பட்ட இஸ்லாமிய சட்டக் கொள்கைகள், (4) வரலாற்று உண்மை. இவற்றுக்கு முரணான உரை, இஸ்னாத் சரியாக இருந்தாலும் சந்தேகத்திற்குரியது.`, si: `හදීසයේ සැබෑ අන්තර්ගතය  –  නබි ﷺ තුමා පැවසූ, කළ, හෝ අනුමත කළ දෑ. මත්න් මෙවාට එරෙහිව ඇගයෙයි: (1) කුර්ආනය, (2) වෙනත් මුතවාතිර් (පුළුල්ව සම්ප්‍රේෂණය වූ) හදීස්, (3) ස්ථාපිත ඉස්ලාමීය නීති මූලධර්ම, සහ (4) ඓතිහාසික යථාර්ථය. මෙවාට පටහැනි පාඨයක්, ඉස්නාද් එක හොඳ වුවද සැක සහිතය.` },
  'structure.ibnmubarak': { en: `Ibn al-Mubarak (d. 181 AH) said: "The isnad is part of the religion. Were it not for the isnad, whoever wished could say whatever he wished." This captures the unique Islamic institution: a chain of human witnesses each vouching for the next, stretching back to the Prophet ﷺ himself.`, ms: `Ibn al-Mubarak (wafat 181 H) berkata: "Isnad adalah sebahagian daripada agama. Sekiranya bukan kerana isnad, sesiapa yang mahu boleh berkata apa sahaja yang dia mahu." Ini menggambarkan institusi Islam yang unik: rangkaian saksi manusia yang masing-masing menjamin yang berikutnya, terbentang kembali sehingga kepada Nabi ﷺ sendiri.`, tur: `İbnü'l-Mübârek (ö. 181 H) şöyle dedi: "İsnad dinin bir parçasıdır. İsnad olmasaydı, dileyen dilediğini söylerdi." Bu, eşsiz İslamî kurumu özetler: her biri bir sonrakine kefil olan ve Peygamber ﷺ'in kendisine kadar uzanan bir insan şahitler zinciri.`, urd: `ابن المبارک (متوفی ۱۸۱ھ) نے کہا: "اسناد دین کا حصہ ہے۔ اگر اسناد نہ ہوتی تو جو چاہتا جو چاہتا کہہ دیتا۔" یہ اسلام کے منفرد ادارے کو بیان کرتا ہے: انسانی گواہوں کا ایک سلسلہ جن میں سے ہر ایک اگلے کی تصدیق کرتا ہے، جو خود نبی ﷺ تک پہنچتا ہے۔`, ben: `ইবনুল মুবারক (মৃ. ১৮১ হিজরি) বলেছেন: "ইসনাদ দীনের অংশ। ইসনাদ না থাকলে যে যা ইচ্ছা বলে দিতে পারত।" এটি ইসলামের অনন্য প্রতিষ্ঠানকে তুলে ধরে: মানব সাক্ষীদের একটি শৃঙ্খল যেখানে প্রত্যেকে পরবর্তীজনের জন্য জামিন, যা স্বয়ং নবী ﷺ পর্যন্ত বিস্তৃত।`, fas: `ابن مبارک (د. ۱۸۱ ق) گفت: «اسناد بخشی از دین است. اگر اسناد نبود، هرکس هرچه می‌خواست می‌گفت.» این، نهاد بی‌نظیر اسلامی را بیان می‌کند: زنجیره‌ای از گواهان انسانی که هریک ضامن بعدی است و تا خود پیامبر ﷺ امتداد می‌یابد.`, zh: `伊本·穆巴拉克（逝于希吉来181年）说："传述链是宗教的一部分。若无传述链，谁想说什么便可说什么。"这道出了伊斯兰独特的制度：一条人证之链，每一位都为下一位作保，一直上溯到先知ﷺ本人。`, yue: `伊本·穆巴拉克（逝於希吉來181年）話："傳述鏈係宗教嘅一部分。若無傳述鏈，邊個想講咩就可以講咩。"呢句道出咗伊斯蘭獨特嘅制度：一條人證之鏈，每一位都為下一位作保，一直上溯到先知ﷺ本人。`, ja: `イブン・アル＝ムバーラク（ヒジュラ暦181年没）は言った。「イスナードは宗教の一部である。イスナードがなければ、望む者は望むままに言えただろう。」これは、イスラム独自の制度を言い表している。すなわち、各々が次を保証する人間の証人の連鎖であり、預言者ﷺご自身にまでさかのぼる。`, ru: `Ибн аль-Мубарак (ум. 181 г. х.) сказал: «Иснад  –  часть религии. Если бы не иснад, всякий говорил бы что пожелает.» Это передаёт уникальный исламский институт: цепь человеческих свидетелей, каждый из которых ручается за следующего, восходящая к самому Пророку ﷺ.`, es: `Ibn al-Mubarak (m. 181 H) dijo: "El isnad es parte de la religión. De no ser por el isnad, quien quisiera podría decir lo que quisiera." Esto resume la institución islámica única: una cadena de testigos humanos que se avalan unos a otros, que se remonta hasta el mismo Profeta ﷺ.`, ko: `이븐 알무바라크(히즈라 181년 사망)는 말했다: "이스나드는 종교의 일부이다. 이스나드가 없었다면 누구든 원하는 것을 원하는 대로 말할 수 있었을 것이다." 이는 이슬람 고유의 제도를 담아낸다: 각자가 다음 사람을 보증하는 인간 증인들의 사슬로서, 예언자 ﷺ 자신에게까지 거슬러 올라간다.`, ta: `இப்னுல் முபாரக் (ஹிஜ்ரி 181இல் மறைந்தார்) கூறினார்: "இஸ்னாத் மார்க்கத்தின் ஒரு பகுதி. இஸ்னாத் இல்லாவிட்டால், விரும்பியவர் விரும்பியதைச் சொல்லியிருப்பார்." இது இஸ்லாத்தின் தனித்துவமான நிறுவனத்தை வெளிப்படுத்துகிறது: ஒவ்வொருவரும் அடுத்தவருக்கு உத்தரவாதம் அளிக்கும் மனித சாட்சிகளின் சங்கிலி, நபி ﷺ அவர்கள் வரை நீளும்.`, si: `ඉබ්නුල් මුබාරක් (හිජ්රි 181 මිය ගිය) මෙසේ කීවේය: "ඉස්නාද් යනු ආගමේ කොටසකි. ඉස්නාද් නොතිබුණේ නම්, කැමති අයෙකුට කැමති දේ කිව හැකිව තිබුණි." මෙය ඉස්ලාමයේ අද්විතීය ආයතනය ප්‍රකාශ කරයි: එක් එක් අය ඊළඟ අයට වගකියන මානව සාක්ෂිකරුවන්ගේ දාමයක්, නබි ﷺ තුමා දක්වාම දිවෙයි.` },

  /* ── Rijal Criticism ─────────────────────────────────────── */
  'rijal.heading': { en: `Rijal Criticism: Ilm al-Jarh wa al-Ta'dil`, ms: `Kritik Rijal: Ilmu al-Jarh wa al-Ta'dil`, tur: `Râvî Tenkidi: İlmü'l-Cerh ve't-Ta'dîl`, urd: `نقدِ رجال: علم الجرح و التعدیل`, ben: `রিজাল সমালোচনা: ইলমুল জারহ ওয়াত তাদিল`, fas: `نقد رجال: علم الجرح و التعدیل`, zh: `传述者评判：贬抑与采信之学`, yue: `傳述者評判：貶抑與採信之學`, ja: `伝承者批判：ジャルフ・ワ・タアディール学`, ru: `Критика передатчиков: ильм аль-джарх ва-т-та'диль`, es: `Crítica de los rijal: Ilm al-Jarh wa al-Ta'dil`, ko: `전승자 비평: 일름 알자르흐 와 알타딜`, ta: `ரிஜால் விமர்சனம்: இல்முல் ஜர்ஹ் வத் தஃதீல்`, si: `රිජාල් විවේචනය: ඉල්ම් අල්-ජර්හ් වත්-තඃදීල්` },
  'rijal.intro': { en: `Ilm al-Rijal ("the science of narrators") is the biographical study of every person who ever narrated a hadith. Ilm al-Jarh wa al-Ta'dil ("the science of disparagement and accreditation") is its evaluative branch  –  scholars would investigate the memory, character, reliability, and consistency of each narrator and issue rulings ranging from "most reliable" to "fabricator."`, ms: `Ilmu al-Rijal ("ilmu para perawi") ialah kajian biografi setiap individu yang pernah meriwayatkan hadith. Ilmu al-Jarh wa al-Ta'dil ("ilmu pencelaan dan pengiktirafan") ialah cabang penilaiannya  –  para ulama akan menyiasat ingatan, perwatakan, kebolehpercayaan, dan ketekalan setiap perawi serta mengeluarkan hukum daripada "paling boleh dipercayai" hingga "pemalsu".`, tur: `İlmü'r-Ricâl ("râvîler ilmi"), hadis rivayet etmiş her kişinin biyografik incelemesidir. İlmü'l-Cerh ve't-Ta'dîl ("cerh ve ta'dil ilmi"), onun değerlendirme dalıdır  –  âlimler her râvînin hafızasını, karakterini, güvenilirliğini ve tutarlılığını araştırır ve "en güvenilir"den "uydurmacı"ya kadar hükümler verirdi.`, urd: `علم الرجال ("راویوں کا علم") ہر اُس شخص کا سوانحی مطالعہ ہے جس نے کبھی حدیث روایت کی۔ علم الجرح و التعدیل ("جرح و تعدیل کا علم") اس کی تشخیصی شاخ ہے  –  علماء ہر راوی کے حافظے، کردار، اعتماد، اور استقامت کی تحقیق کرتے اور "سب سے معتبر" سے "وضّاع" تک کے احکام جاری کرتے۔`, ben: `ইলমুর রিজাল ("বর্ণনাকারীদের শাস্ত্র") হলো যে কেউ কখনো হাদিস বর্ণনা করেছেন তাঁর জীবনীমূলক অধ্যয়ন। ইলমুল জারহ ওয়াত তাদিল ("নিন্দা ও স্বীকৃতির শাস্ত্র") হলো এর মূল্যায়নমূলক শাখা  –  আলেমগণ প্রতিটি বর্ণনাকারীর স্মৃতি, চরিত্র, নির্ভরযোগ্যতা ও সামঞ্জস্য অনুসন্ধান করতেন এবং "সর্বাধিক নির্ভরযোগ্য" থেকে "জালিয়াত" পর্যন্ত রায় দিতেন।`, fas: `علم الرجال («دانش راویان») مطالعه‌ی زندگی‌نامه‌ای هر کسی است که روزی حدیث روایت کرده است. علم الجرح و التعدیل («دانش جرح و تعدیل») شاخه‌ی ارزیابی آن است  –  علما حافظه، شخصیت، اعتمادپذیری و ثبات هر راوی را بررسی می‌کردند و احکامی از «معتمدترین» تا «جعل‌کننده» صادر می‌کردند.`, zh: `传述者学（"传述者之学"）是对每一位曾传述圣训之人的生平研究。贬抑与采信之学（"贬抑与采信之学"）是其评判分支  –  学者会考察每位传述者的记忆、品行、可信度与一致性，作出从"最可信"到"伪造者"的裁断。`, yue: `傳述者學（"傳述者之學"）係對每一位曾傳述聖訓之人嘅生平研究。貶抑與採信之學（"貶抑與採信之學"）係其評判分支  –  學者會考察每位傳述者嘅記憶、品行、可信度同一致性，作出由"最可信"到"偽造者"嘅裁斷。`, ja: `イルム・アッ＝リジャール（「伝承者の学」）は、かつてハディースを伝えたすべての人物の伝記的研究である。イルム・アル＝ジャルフ・ワ・アッ＝タアディール（「批判と公認の学」）はその評価部門であり  –  学者は各伝承者の記憶・人格・信頼性・一貫性を調べ、「最も信頼できる」から「捏造者」までの判定を下した。`, ru: `Ильм ар-риджаль («наука о передатчиках»)  –  это биографическое изучение каждого, кто когда-либо передавал хадис. Ильм аль-джарх ва-т-та'диль («наука порицания и удостоверения»)  –  её оценочная ветвь  –  учёные исследовали память, нрав, надёжность и последовательность каждого передатчика и выносили суждения от «надёжнейшего» до «измыслителя».`, es: `El Ilm al-Rijal ("la ciencia de los narradores") es el estudio biográfico de toda persona que alguna vez narró un hadiz. El Ilm al-Jarh wa al-Ta'dil ("la ciencia de la descalificación y la acreditación") es su rama evaluativa  –  los sabios investigaban la memoria, el carácter, la fiabilidad y la coherencia de cada narrador y emitían dictámenes que iban de "el más fiable" a "falsificador".`, ko: `일름 알리잘("전승자의 학문")은 하디스를 전한 적 있는 모든 사람에 대한 전기적 연구이다. 일름 알자르흐 와 알타딜("폄하와 인정의 학문")은 그 평가 분과로서  –  학자들은 각 전승자의 기억, 인격, 신뢰성, 일관성을 조사하여 "가장 신뢰할 만함"에서 "위조자"에 이르는 판정을 내렸다.`, ta: `இல்முர் ரிஜால் ("அறிவிப்பாளர் அறிவியல்") என்பது எப்போதேனும் ஹதீஸ் அறிவித்த ஒவ்வொருவரின் வாழ்க்கை வரலாற்று ஆய்வு. இல்முல் ஜர்ஹ் வத் தஃதீல் ("இகழ்வு மற்றும் அங்கீகாரத்தின் அறிவியல்") அதன் மதிப்பீட்டுக் கிளை  –  அறிஞர்கள் ஒவ்வொரு அறிவிப்பாளரின் நினைவாற்றல், குணம், நம்பகத்தன்மை, நிலைத்தன்மை ஆகியவற்றை ஆராய்ந்து "மிகவும் நம்பகமானவர்" முதல் "இட்டுக்கட்டுபவர்" வரை தீர்ப்புகள் வழங்கினர்.`, si: `ඉල්ම් අර්-රිජාල් ("වාර්තාකරුවන්ගේ විද්‍යාව") යනු කවදා හෝ හදීසයක් වාර්තා කළ සෑම පුද්ගලයෙකුගේම චරිතාපදාන අධ්‍යයනයයි. ඉල්ම් අල්-ජර්හ් වත්-තඃදීල් ("හෙළාදැකීම සහ පිළිගැනීමේ විද්‍යාව") එහි ඇගයීම් අංශයයි  –  විද්වතුන් සෑම වාර්තාකරුවෙකුගේම මතකය, චරිතය, විශ්වාසනීයත්වය සහ අනුකූලතාව විමර්ශනය කර "වඩාත්ම විශ්වාසනීය" සිට "ව්‍යාජ නිර්මාණකරු" දක්වා තීන්දු නිකුත් කළහ.` },
  'rijal.1.level': { en: `Thiqa (Trustworthy)`, ms: `Thiqa (Boleh Dipercayai)`, tur: `Sika (Güvenilir)`, urd: `ثقہ (قابلِ اعتماد)`, ben: `সিকাহ (নির্ভরযোগ্য)`, fas: `ثقه (مورد اعتماد)`, zh: `可信（西格）`, yue: `可信（西格）`, ja: `シカ（信頼できる）`, ru: `Сика (надёжный)`, es: `Thiqa (fiable)`, ko: `시카 (신뢰할 만함)`, ta: `ஸிகா (நம்பகமான)`, si: `සිකා (විශ්වාසනීය)` },
  'rijal.1.detail': { en: `Full confidence in the narrator's uprightness and memory. The strongest endorsement.`, ms: `Keyakinan penuh terhadap ketulusan dan ingatan perawi. Pengiktirafan paling kuat.`, tur: `Râvînin doğruluğuna ve hafızasına tam güven. En güçlü tezkiye.`, urd: `راوی کی دیانت اور حافظے پر مکمل اعتماد۔ سب سے مضبوط توثیق۔`, ben: `বর্ণনাকারীর সততা ও স্মৃতির ওপর পূর্ণ আস্থা। সবচেয়ে শক্তিশালী স্বীকৃতি।`, fas: `اعتماد کامل به درستی و حافظه‌ی راوی. قوی‌ترین توثیق.`, zh: `对传述者正直与记忆的充分信任。最有力的认可。`, yue: `對傳述者正直同記憶嘅充分信任。最有力嘅認可。`, ja: `伝承者の正しさと記憶への全幅の信頼。最も強い裏書き。`, ru: `Полное доверие к честности и памяти передатчика. Сильнейшее одобрение.`, es: `Plena confianza en la rectitud y la memoria del narrador. El respaldo más fuerte.`, ko: `전승자의 올곧음과 기억에 대한 완전한 신뢰. 가장 강력한 인정.`, ta: `அறிவிப்பாளரின் நேர்மை மற்றும் நினைவாற்றலில் முழு நம்பிக்கை. மிக வலுவான அங்கீகாரம்.`, si: `වාර්තාකරුගේ අවංකභාවය හා මතකය කෙරෙහි පූර්ණ විශ්වාසය. ප්‍රබලම අනුමැතිය.` },
  'rijal.2.level': { en: `Saduq (Truthful)`, ms: `Saduq (Benar)`, tur: `Sadûk (Doğru Sözlü)`, urd: `صدوق (سچا)`, ben: `সাদুক (সত্যবাদী)`, fas: `صدوق (راستگو)`, zh: `诚实（萨杜格）`, yue: `誠實（薩杜格）`, ja: `サドゥーク（誠実）`, ru: `Садук (правдивый)`, es: `Saduq (veraz)`, ko: `사두크 (진실한)`, ta: `ஸதூக் (உண்மையான)`, si: `සදූක් (සත්‍යවාදී)` },
  'rijal.2.detail': { en: `Generally reliable but with occasional lapses in memory. Hadiths are accepted with slight caution.`, ms: `Umumnya boleh dipercayai tetapi sekali-sekala tersilap ingatan. Hadith diterima dengan sedikit kewaspadaan.`, tur: `Genelde güvenilir ama ara sıra hafıza kaymaları olur. Hadisleri hafif ihtiyatla kabul edilir.`, urd: `عموماً قابلِ اعتماد لیکن کبھی کبھار حافظے میں لغزش۔ احادیث تھوڑی احتیاط کے ساتھ قبول کی جاتی ہیں۔`, ben: `সাধারণত নির্ভরযোগ্য তবে মাঝে মাঝে স্মৃতিভ্রংশ। হাদিস সামান্য সতর্কতার সাথে গৃহীত হয়।`, fas: `عموماً معتمد اما گاهی دچار لغزش حافظه. احادیث با اندکی احتیاط پذیرفته می‌شود.`, zh: `大体可信，但偶有记忆失误。其圣训略加审慎而被接受。`, yue: `大體可信，但偶有記憶失誤。其聖訓略加審慎而被接受。`, ja: `おおむね信頼できるが、時に記憶の失誤がある。ハディースはわずかな慎重さをもって受け入れられる。`, ru: `В целом надёжен, но с редкими провалами памяти. Хадисы принимаются с лёгкой осторожностью.`, es: `Generalmente fiable, pero con lapsos ocasionales de memoria. Sus hadices se aceptan con leve cautela.`, ko: `대체로 신뢰할 만하나 때때로 기억의 착오가 있음. 하디스는 약간의 주의와 함께 받아들여진다.`, ta: `பொதுவாக நம்பகமானவர் ஆனால் அவ்வப்போது நினைவுப் பிழைகள் உண்டு. ஹதீஸ்கள் சிறிது எச்சரிக்கையுடன் ஏற்கப்படுகின்றன.`, si: `සාමාන්‍යයෙන් විශ්වාසනීය නමුත් ඉඳහිට මතක දෝෂ ඇත. හදීස් සුළු ප්‍රවේශමකින් පිළිගනු ලැබේ.` },
  'rijal.3.level': { en: `Da'if (Weak)`, ms: `Da'if (Lemah)`, tur: `Zayıf (Zayıf)`, urd: `ضعیف (کمزور)`, ben: `যইফ (দুর্বল)`, fas: `ضعیف (ضعیف)`, zh: `弱（达伊夫）`, yue: `弱（達伊夫）`, ja: `ダイーフ（弱い）`, ru: `Даиф (слабый)`, es: `Da'if (débil)`, ko: `다이프 (약함)`, ta: `ளயீஃப் (பலவீனம்)`, si: `දයීෆ් (දුර්වල)` },
  'rijal.3.detail': { en: `Narrators whose memory or character is deficient enough to undermine trust, but not fabricators.`, ms: `Perawi yang ingatan atau perwatakannya cacat sehingga menjejaskan kepercayaan, tetapi bukan pemalsu.`, tur: `Hafızası ya da karakteri güveni sarsacak kadar kusurlu olan, ancak uydurmacı olmayan râvîler.`, urd: `وہ راوی جن کا حافظہ یا کردار اعتماد کو متزلزل کرنے کی حد تک ناقص ہے، مگر وہ وضّاع نہیں۔`, ben: `যেসব বর্ণনাকারীর স্মৃতি বা চরিত্র আস্থা ক্ষুণ্ণ করার মতো ত্রুটিপূর্ণ, কিন্তু জালিয়াত নন।`, fas: `راویانی که حافظه یا شخصیتشان آن‌قدر معیوب است که اعتماد را سست می‌کند، اما جعل‌کننده نیستند.`, zh: `记忆或品行有缺、足以削弱信任的传述者，但并非伪造者。`, yue: `記憶或品行有缺、足以削弱信任嘅傳述者，但並非偽造者。`, ja: `記憶や人格に欠陥があって信頼を損なうほどだが、捏造者ではない伝承者。`, ru: `Передатчики, чья память или нрав достаточно ущербны, чтобы подорвать доверие, но не измыслители.`, es: `Narradores cuya memoria o carácter es lo bastante deficiente como para minar la confianza, pero no falsificadores.`, ko: `기억이나 인격이 신뢰를 무너뜨릴 만큼 결함이 있으나 위조자는 아닌 전승자.`, ta: `நினைவாற்றலோ குணமோ நம்பிக்கையைக் குலைக்கும் அளவுக்குக் குறைபாடுடைய அறிவிப்பாளர்கள், ஆனால் இட்டுக்கட்டுபவர்கள் அல்ல.`, si: `මතකය හෝ චරිතය විශ්වාසය බිඳ දමන තරම් අඩුපාඩු සහිත වාර්තාකරුවන්, නමුත් ව්‍යාජ නිර්මාණකරුවන් නොවේ.` },
  'rijal.4.level': { en: `Matruk (Abandoned)`, ms: `Matruk (Ditinggalkan)`, tur: `Metrûk (Terk Edilmiş)`, urd: `متروک (متروک)`, ben: `মাতরুক (পরিত্যক্ত)`, fas: `متروک (متروک)`, zh: `被弃（迈特鲁克）`, yue: `被棄（邁特魯克）`, ja: `マトルーク（放棄された）`, ru: `Матрук (оставленный)`, es: `Matruk (abandonado)`, ko: `마트루크 (버려진)`, ta: `மத்ரூக் (கைவிடப்பட்ட)`, si: `මත්රූක් (අත්හළ)` },
  'rijal.4.detail': { en: `Narrators whose hadiths are abandoned because of frequent serious errors or open wickedness.`, ms: `Perawi yang hadithnya ditinggalkan kerana kesilapan serius yang kerap atau kejahatan yang terang-terangan.`, tur: `Sık ve ciddi hatalar ya da açık fısk sebebiyle hadisleri terk edilen râvîler.`, urd: `وہ راوی جن کی احادیث بار بار سنگین غلطیوں یا کھلی بدکرداری کے سبب ترک کر دی جاتی ہیں۔`, ben: `ঘন ঘন গুরুতর ভুল বা প্রকাশ্য পাপাচারের কারণে যেসব বর্ণনাকারীর হাদিস পরিত্যক্ত হয়।`, fas: `راویانی که حدیث‌هایشان به سبب خطاهای جدی مکرر یا فسق آشکار رها می‌شود.`, zh: `因屡犯严重错误或公开为非而其圣训被弃置的传述者。`, yue: `因屢犯嚴重錯誤或公開為非而其聖訓被棄置嘅傳述者。`, ja: `重大な誤りを頻繁に犯すか、公然たる悪行のために、そのハディースが放棄される伝承者。`, ru: `Передатчики, чьи хадисы оставлены из-за частых серьёзных ошибок или явного нечестия.`, es: `Narradores cuyos hadices se abandonan por errores graves frecuentes o maldad manifiesta.`, ko: `잦은 중대한 오류나 공공연한 사악함 때문에 그 하디스가 버려지는 전승자.`, ta: `அடிக்கடி கடுமையான தவறுகள் அல்லது வெளிப்படையான தீச்செயல்களால் ஹதீஸ்கள் கைவிடப்படும் அறிவிப்பாளர்கள்.`, si: `නිතර බරපතල වැරදි හෝ විවෘත දුෂ්ටකම් නිසා හදීස් අත්හරින වාර්තාකරුවන්.` },
  'rijal.5.level': { en: `Kadhdhab (Liar)`, ms: `Kadhdhab (Pendusta)`, tur: `Kezzâb (Yalancı)`, urd: `کذّاب (جھوٹا)`, ben: `কাযযাব (মিথ্যাবাদী)`, fas: `کذّاب (دروغگو)`, zh: `说谎者（卡扎布）`, yue: `講大話者（卡扎布）`, ja: `カッザーブ（嘘つき）`, ru: `Каззаб (лжец)`, es: `Kadhdhab (mentiroso)`, ko: `카드답 (거짓말쟁이)`, ta: `கத்தாப் (பொய்யர்)`, si: `කද්දාබ් (බොරුකාරයා)` },
  'rijal.5.detail': { en: `A narrator caught fabricating hadiths. All their narrations are rejected entirely.`, ms: `Perawi yang didapati memalsukan hadith. Semua riwayatnya ditolak sepenuhnya.`, tur: `Hadis uydururken yakalanan râvî. Bütün rivayetleri tamamen reddedilir.`, urd: `وہ راوی جو احادیث گھڑتے ہوئے پکڑا گیا۔ اس کی تمام روایات کلیتاً مسترد کر دی جاتی ہیں۔`, ben: `হাদিস জাল করতে ধরা পড়া বর্ণনাকারী। তাঁর সব বর্ণনা সম্পূর্ণ প্রত্যাখ্যাত।`, fas: `راوی‌ای که در حال جعل حدیث گرفتار شده است. تمام روایاتش به‌کلی رد می‌شود.`, zh: `被当场抓获伪造圣训的传述者。其一切传述全然被弃。`, yue: `被當場抓獲偽造聖訓嘅傳述者。其一切傳述全然被棄。`, ja: `ハディースを捏造しているところを見つかった伝承者。その伝承はすべて完全に却下される。`, ru: `Передатчик, уличённый в измышлении хадисов. Все его предания отвергаются полностью.`, es: `Un narrador sorprendido fabricando hadices. Todas sus narraciones se rechazan por completo.`, ko: `하디스를 위조하다 발각된 전승자. 그의 모든 전승은 전적으로 거부된다.`, ta: `ஹதீஸ்களை இட்டுக்கட்டுகையில் பிடிபட்ட அறிவிப்பாளர். அவரது அனைத்து அறிவிப்புகளும் முற்றிலும் நிராகரிக்கப்படுகின்றன.`, si: `හදීස් ව්‍යාජ ලෙස නිර්මාණය කරද්දී අල්ලා ගත් වාර්තාකරුවෙක්. ඔහුගේ සියලු වාර්තා සම්පූර්ණයෙන් ප්‍රතික්ෂේප වේ.` },
  'rijal.6.level': { en: `Majhul (Unknown)`, ms: `Majhul (Tidak Dikenali)`, tur: `Mechûl (Bilinmeyen)`, urd: `مجہول (نامعلوم)`, ben: `মাজহুল (অজ্ঞাত)`, fas: `مجهول (ناشناخته)`, zh: `不明（迈杰胡勒）`, yue: `不明（邁傑胡勒）`, ja: `マジュフール（未知）`, ru: `Маджхуль (неизвестный)`, es: `Majhul (desconocido)`, ko: `마즈훌 (미상)`, ta: `மஜ்ஹூல் (அறியப்படாதவர்)`, si: `මජ්හූල් (නොදන්නා)` },
  'rijal.6.detail': { en: `A narrator whose character or identity cannot be verified. Majority: hadiths not accepted without supporting evidence.`, ms: `Perawi yang perwatakan atau identitinya tidak dapat disahkan. Majoriti: hadith tidak diterima tanpa bukti sokongan.`, tur: `Karakteri ya da kimliği doğrulanamayan râvî. Çoğunluk: destekleyici delil olmadan hadisleri kabul edilmez.`, urd: `وہ راوی جس کے کردار یا شناخت کی تصدیق نہ ہو سکے۔ اکثریت: تائیدی شواہد کے بغیر احادیث قبول نہیں۔`, ben: `যে বর্ণনাকারীর চরিত্র বা পরিচয় যাচাই করা যায় না। অধিকাংশ: সমর্থক প্রমাণ ছাড়া হাদিস গৃহীত নয়।`, fas: `راوی‌ای که شخصیت یا هویتش قابل تأیید نیست. اکثریت: احادیثش بدون شواهد پشتیبان پذیرفته نمی‌شود.`, zh: `品行或身份无法核实的传述者。多数：无佐证则其圣训不被接受。`, yue: `品行或身份無法核實嘅傳述者。多數：無佐證則其聖訓不被接受。`, ja: `人格や身元を確認できない伝承者。多数派：裏づけとなる証拠なしにはハディースは受け入れられない。`, ru: `Передатчик, чьи нрав или личность нельзя удостоверить. Большинство: хадисы не принимаются без подтверждающих свидетельств.`, es: `Un narrador cuyo carácter o identidad no se puede verificar. Mayoría: sus hadices no se aceptan sin pruebas de apoyo.`, ko: `인격이나 신원을 확인할 수 없는 전승자. 다수설: 뒷받침 증거 없이는 하디스가 받아들여지지 않음.`, ta: `குணமோ அடையாளமோ சரிபார்க்க முடியாத அறிவிப்பாளர். பெரும்பான்மை: ஆதரவு சான்றின்றி ஹதீஸ்கள் ஏற்கப்படுவதில்லை.`, si: `චරිතය හෝ අනන්‍යතාව සත්‍යාපනය කළ නොහැකි වාර්තාකරුවෙක්. බහුතරය: සහාය සාක්ෂි නොමැතිව හදීස් පිළිගනු නොලැබේ.` },

  /* ── Five Conditions ─────────────────────────────────────── */
  'conditions.heading': { en: `The Five Conditions for a Sahih Hadith`, ms: `Lima Syarat Hadith Sahih`, tur: `Sahih Hadisin Beş Şartı`, urd: `حدیثِ صحیح کی پانچ شرائط`, ben: `সহিহ হাদিসের পাঁচ শর্ত`, fas: `پنج شرط حدیث صحیح`, zh: `真实圣训的五项条件`, yue: `真實聖訓嘅五項條件`, ja: `サヒーフ・ハディースの五条件`, ru: `Пять условий достоверного хадиса`, es: `Las cinco condiciones de un hadiz sahih`, ko: `사히흐 하디스의 다섯 조건`, ta: `ஸஹீஹ் ஹதீஸுக்கான ஐந்து நிபந்தனைகள்`, si: `සහීහ් හදීසයක පංච කොන්දේසි` },
  'conditions.1.title': { en: `Ittisal al-Sanad`, ms: `Ittisal al-Sanad`, tur: `Ittisâlü's-Sened`, urd: `اتصالِ سند`, ben: `ইত্তিসালুস সানাদ`, fas: `اتصال سند`, zh: `传述链相连（Ittisal al-Sanad）`, yue: `傳述鏈相連（Ittisal al-Sanad）`, ja: `イッティサール・アッ＝サナド`, ru: `Иттисаль ас-санад`, es: `Ittisal al-Sanad`, ko: `잇티살 알사나드`, ta: `இத்திஸாலுஸ் ஸனத்`, si: `ඉත්තිසාල් අස්-සනද්` },
  'conditions.1.body': { en: `The chain must be unbroken  –  every narrator must have met and received the hadith directly from the one above him.`, ms: `Rangkaian sanad mestilah tidak terputus  –  setiap perawi mesti pernah bertemu dan menerima hadith secara langsung daripada orang di atasnya.`, tur: `Zincir kesintisiz olmalı  –  her râvî, kendinden öncekiyle görüşmüş ve hadisi doğrudan ondan almış olmalıdır.`, urd: `سند متصل ہونی چاہیے  –  ہر راوی نے اپنے اوپر والے سے ملاقات کی ہو اور حدیث براہِ راست اسی سے لی ہو۔`, ben: `সনদ অবিচ্ছিন্ন হতে হবে  –  প্রত্যেক বর্ণনাকারীকে তাঁর ঊর্ধ্বতনের সাথে সাক্ষাৎ করে সরাসরি তাঁর কাছ থেকে হাদিস গ্রহণ করতে হবে।`, fas: `سند باید پیوسته باشد  –  هر راوی باید با راوی پیش از خود دیدار کرده و حدیث را مستقیماً از او گرفته باشد.`, zh: `传述链必须连贯  –  每位传述者都须曾会见其上一位，并直接从他领受圣训。`, yue: `傳述鏈必須連貫  –  每位傳述者都須曾會見其上一位，並直接從佢領受聖訓。`, ja: `連鎖は途切れてはならない  –  各伝承者は、自分の上の者に会い、その者から直接ハディースを受け取っていなければならない。`, ru: `Цепь должна быть непрерывной  –  каждый передатчик должен был встретиться с тем, кто выше него, и получить хадис непосредственно от него.`, es: `La cadena debe ser ininterrumpida  –  cada narrador debe haberse encontrado con el anterior y haber recibido el hadiz directamente de él.`, ko: `사슬은 끊김이 없어야 한다  –  각 전승자는 자기 위의 사람을 만나 그로부터 직접 하디스를 받았어야 한다.`, ta: `சங்கிலி அறுபடாமல் இருக்க வேண்டும்  –  ஒவ்வொரு அறிவிப்பாளரும் தமக்கு மேல் உள்ளவரைச் சந்தித்து, அவரிடமிருந்து நேரடியாக ஹதீஸைப் பெற்றிருக்க வேண்டும்.`, si: `දාමය නොකැඩී තිබිය යුතුය  –  සෑම වාර්තාකරුවෙකුම තමාට ඉහළින් සිටින අයා හමු වී, ඔහුගෙන් සෘජුව හදීසය ලබාගෙන තිබිය යුතුය.` },
  'conditions.2.title': { en: `'Adalah (Uprightness)`, ms: `'Adalah (Ketulusan)`, tur: `Adâlet (Doğruluk)`, urd: `عدالت (دیانت)`, ben: `আদালাহ (সততা)`, fas: `عدالت (درستکاری)`, zh: `公正（阿达莱）`, yue: `公正（阿達萊）`, ja: `アダーラ（公正さ）`, ru: `Адаля (праведность)`, es: `'Adalah (rectitud)`, ko: `아달라 (올곧음)`, ta: `அதாலா (நேர்மை)`, si: `අදාලා (අවංකභාවය)` },
  'conditions.2.body': { en: `Every narrator in the chain must be a trustworthy Muslim free from major sins and acts that compromise character.`, ms: `Setiap perawi dalam rangkaian mestilah seorang Muslim yang boleh dipercayai, bebas daripada dosa besar dan perbuatan yang mencacatkan perwatakan.`, tur: `Zincirdeki her râvî, büyük günahlardan ve karakteri zedeleyen fiillerden uzak, güvenilir bir Müslüman olmalıdır.`, urd: `سند میں ہر راوی ایک قابلِ اعتماد مسلمان ہونا چاہیے جو کبیرہ گناہوں اور کردار کو مجروح کرنے والے اعمال سے پاک ہو۔`, ben: `শৃঙ্খলের প্রত্যেক বর্ণনাকারীকে এমন নির্ভরযোগ্য মুসলিম হতে হবে যিনি কবিরা গুনাহ ও চরিত্রহানিকর কাজ থেকে মুক্ত।`, fas: `هر راوی در زنجیره باید مسلمانی مورد اعتماد باشد، به دور از گناهان کبیره و کارهایی که شخصیت را خدشه‌دار می‌کند.`, zh: `链中每位传述者都须是可信的穆斯林，远离大罪及有损品行的行为。`, yue: `鏈中每位傳述者都須係可信嘅穆斯林，遠離大罪及有損品行嘅行為。`, ja: `連鎖の各伝承者は、大罪や人格を損なう行いから免れた、信頼できるムスリムでなければならない。`, ru: `Каждый передатчик в цепи должен быть надёжным мусульманином, свободным от великих грехов и поступков, порочащих нрав.`, es: `Cada narrador de la cadena debe ser un musulmán fiable, libre de pecados graves y de actos que comprometan el carácter.`, ko: `사슬의 각 전승자는 대죄와 인격을 훼손하는 행위에서 자유로운 신뢰할 만한 무슬림이어야 한다.`, ta: `சங்கிலியில் உள்ள ஒவ்வொரு அறிவிப்பாளரும், பெரும்பாவங்கள் மற்றும் குணத்தைக் கெடுக்கும் செயல்களிலிருந்து விடுபட்ட நம்பகமான முஸ்லிமாக இருக்க வேண்டும்.`, si: `දාමයේ සෑම වාර්තාකරුවෙකුම, මහා පාප සහ චරිතය විනාශ කරන ක්‍රියාවලින් තොර, විශ්වාසනීය මුස්ලිම්වරයෙකු විය යුතුය.` },
  'conditions.3.title': { en: `Dabt (Precision)`, ms: `Dabt (Ketepatan)`, tur: `Zabt (Hassasiyet)`, urd: `ضبط (پختگی)`, ben: `যাবত (নির্ভুলতা)`, fas: `ضبط (دقت)`, zh: `精准（达卜特）`, yue: `精準（達卜特）`, ja: `ダブト（正確さ）`, ru: `Дабт (точность)`, es: `Dabt (precisión)`, ko: `다브트 (정확성)`, ta: `ளப்த் (துல்லியம்)`, si: `දබ්ත් (නිරවද්‍යතාව)` },
  'conditions.3.body': { en: `Every narrator must have an accurate memory  –  either preserving the hadith in their chest (hafiz) or in reliable written records (kitab).`, ms: `Setiap perawi mesti mempunyai ingatan yang tepat  –  sama ada memelihara hadith dalam dadanya (hafiz) atau dalam catatan bertulis yang boleh dipercayai (kitab).`, tur: `Her râvînin doğru bir hafızası olmalı  –  hadisi ya gönlünde (hâfız) ya da güvenilir yazılı kayıtlarda (kitap) korumalı.`, urd: `ہر راوی کا حافظہ درست ہونا چاہیے  –  یا تو حدیث کو اپنے سینے میں محفوظ رکھے (حافظ) یا قابلِ اعتماد تحریری ریکارڈ میں (کتاب)۔`, ben: `প্রত্যেক বর্ণনাকারীর নির্ভুল স্মৃতি থাকতে হবে  –  হয় হাদিস তাঁর বুকে সংরক্ষণ করে (হাফিজ) অথবা নির্ভরযোগ্য লিখিত নথিতে (কিতাব)।`, fas: `هر راوی باید حافظه‌ای دقیق داشته باشد  –  یا حدیث را در سینه‌اش نگه دارد (حافظ) یا در نوشته‌های معتبر (کتاب).`, zh: `每位传述者都须有准确的记忆  –  或将圣训存于胸中（哈菲兹），或存于可靠的书面记录（基塔卜）。`, yue: `每位傳述者都須有準確嘅記憶  –  或將聖訓存於胸中（哈菲茲），或存於可靠嘅書面記錄（基塔卜）。`, ja: `各伝承者は正確な記憶を持たねばならない  –  ハディースを胸中に保つ（ハーフィズ）か、信頼できる書面記録（キターブ）に保つかである。`, ru: `Каждый передатчик должен обладать точной памятью  –  храня хадис либо в груди (хафиз), либо в надёжных письменных записях (китаб).`, es: `Cada narrador debe tener una memoria precisa  –  ya sea preservando el hadiz en su pecho (hafiz) o en registros escritos fiables (kitab).`, ko: `각 전승자는 정확한 기억을 지녀야 한다  –  하디스를 가슴에 간직하거나(하피즈) 신뢰할 만한 문헌 기록(키타브)에 간직함이다.`, ta: `ஒவ்வொரு அறிவிப்பாளரும் துல்லியமான நினைவாற்றல் கொண்டிருக்க வேண்டும்  –  ஹதீஸை மனத்தில் பாதுகாப்பது (ஹாஃபிழ்) அல்லது நம்பகமான எழுத்துப் பதிவுகளில் (கிதாப்).`, si: `සෑම වාර්තාකරුවෙකුටම නිවැරදි මතකයක් තිබිය යුතුය  –  හදීසය ළැපැත්තේ (හාෆිස්) හෝ විශ්වසනීය ලිඛිත වාර්තාවල (කිතාබ්) රැක ගැනීම.` },
  'conditions.4.title': { en: `Shudhudh (No Anomaly)`, ms: `Shudhudh (Tiada Keganjilan)`, tur: `Şüzûz (Aykırılık Yokluğu)`, urd: `شذوذ (عدمِ شذوذ)`, ben: `শুযূয (অসংগতিহীনতা)`, fas: `شذوذ (نبود ناهنجاری)`, zh: `反常（无反常，舒祖兹）`, yue: `反常（無反常，舒祖茲）`, ja: `シュズーズ（変則がないこと）`, ru: `Шузуз (отсутствие аномалии)`, es: `Shudhudh (sin anomalía)`, ko: `슈두드 (변칙 없음)`, ta: `ஷுதூத் (முரண் இன்மை)`, si: `ෂුදූද් (විෂමතාවක් නැති බව)` },
  'conditions.4.body': { en: `The hadith must not contradict a more reliable narration from a stronger narrator  –  the rule of the majority over the lone narrator.`, ms: `Hadith tidak boleh bertentangan dengan riwayat yang lebih boleh dipercayai daripada perawi yang lebih kuat  –  kaedah majoriti mengatasi perawi yang bersendirian.`, tur: `Hadis, daha güçlü bir râvîden gelen daha güvenilir bir rivayetle çelişmemeli  –  çoğunluğun tek râvîye üstün gelmesi kuralı.`, urd: `حدیث کسی زیادہ قوی راوی کی زیادہ معتبر روایت سے متصادم نہیں ہونی چاہیے  –  تنہا راوی پر اکثریت کے غلبے کا اصول۔`, ben: `হাদিস কোনো শক্তিশালী বর্ণনাকারীর অধিকতর নির্ভরযোগ্য বর্ণনার বিরোধী হতে পারবে না  –  একক বর্ণনাকারীর ওপর সংখ্যাগরিষ্ঠের প্রাধান্যের নিয়ম।`, fas: `حدیث نباید با روایتی معتبرتر از راوی‌ای قوی‌تر در تضاد باشد  –  قاعده‌ی برتری اکثریت بر راوی تنها.`, zh: `圣训不得与更强传述者更可靠的传述相抵触  –  即多数胜过孤证之则。`, yue: `聖訓不得與更強傳述者更可靠嘅傳述相抵觸  –  即多數勝過孤證之則。`, ja: `ハディースは、より強い伝承者からのより信頼できる伝承と矛盾してはならない  –  単独の伝承者に対する多数の優位という規則である。`, ru: `Хадис не должен противоречить более надёжному преданию от более сильного передатчика  –  правило преобладания большинства над одиночным передатчиком.`, es: `El hadiz no debe contradecir una narración más fiable de un narrador más fuerte  –  la regla de la mayoría sobre el narrador solitario.`, ko: `하디스는 더 강한 전승자의 더 신뢰할 만한 전승과 모순되어서는 안 된다  –  단독 전승자에 대한 다수의 우위 원칙.`, ta: `ஹதீஸ், வலுவான அறிவிப்பாளரின் அதிக நம்பகமான அறிவிப்புக்கு முரணாக இருக்கக் கூடாது  –  தனி அறிவிப்பாளர் மீது பெரும்பான்மையின் மேலாதிக்க விதி.`, si: `හදීසය, වඩා ශක්තිමත් වාර්තාකරුවෙකුගේ වඩා විශ්වාසනීය වාර්තාවකට පටහැනි නොවිය යුතුය  –  තනි වාර්තාකරුට වඩා බහුතරයේ ආධිපත්‍යයේ නියමය.` },
  'conditions.5.title': { en: `'Illah (No Hidden Defect)`, ms: `'Illah (Tiada Kecacatan Tersembunyi)`, tur: `İllet (Gizli Kusur Yokluğu)`, urd: `علت (عدمِ خفی عیب)`, ben: `ইল্লাহ (গোপন ত্রুটিহীনতা)`, fas: `علت (نبود عیب پنهان)`, zh: `隐疾（无隐疾，伊莱）`, yue: `隱疾（無隱疾，伊萊）`, ja: `イッラ（隠れた欠陥がないこと）`, ru: `Илля (отсутствие скрытого изъяна)`, es: `'Illah (sin defecto oculto)`, ko: `일라 (숨은 결함 없음)`, ta: `இல்லா (மறைந்த குறை இன்மை)`, si: `ඉල්ලා (සැඟවුණු දෝෂයක් නැති බව)` },
  'conditions.5.body': { en: `There must be no subtle, concealed defect that undermines authenticity  –  discoverable only by master hadith critics (naqad al-hadith).`, ms: `Tidak boleh ada kecacatan halus dan tersembunyi yang menjejaskan kesahihan  –  hanya dapat dikesan oleh para pengkritik hadith yang mahir (naqad al-hadith).`, tur: `Sıhhati zedeleyen ince, gizli bir kusur bulunmamalı  –  yalnızca usta hadis tenkitçileri (nükkad el-hadis) tarafından keşfedilebilir.`, urd: `کوئی ایسا لطیف، پوشیدہ عیب نہیں ہونا چاہیے جو صحت کو مجروح کرے  –  جسے صرف ماہر نقّادِ حدیث (نقّاد الحدیث) ہی دریافت کر سکتے ہیں۔`, ben: `এমন কোনো সূক্ষ্ম, গোপন ত্রুটি থাকা যাবে না যা সত্যতাকে ক্ষুণ্ণ করে  –  যা কেবল পারদর্শী হাদিস-সমালোচকরা (নুক্কাদুল হাদিস) আবিষ্কার করতে পারেন।`, fas: `نباید عیبی ظریف و پنهان وجود داشته باشد که صحت را خدشه‌دار کند  –  که تنها ناقدان برجسته‌ی حدیث (نقّاد الحدیث) آن را کشف می‌کنند.`, zh: `不得有损害真实性的细微隐藏缺陷  –  唯有圣训鉴定大师（圣训批评家）方能察觉。`, yue: `不得有損害真實性嘅細微隱藏缺陷  –  唯有聖訓鑑定大師（聖訓批評家）方能察覺。`, ja: `真正性を損なう、微妙で隠れた欠陥があってはならない  –  熟練のハディース批評家（ナッカード・アル＝ハディース）のみが見つけられる。`, ru: `Не должно быть тонкого, скрытого изъяна, подрывающего достоверность  –  обнаружимого лишь мастерами критики хадиса (наккад аль-хадис).`, es: `No debe haber un defecto sutil y oculto que mine la autenticidad  –  detectable solo por los maestros críticos del hadiz (nuqqad al-hadith).`, ko: `진정성을 훼손하는 미묘하고 숨겨진 결함이 없어야 한다  –  오직 숙련된 하디스 비평가(눅카드 알하디스)만이 발견할 수 있다.`, ta: `சரித்தன்மையைக் குலைக்கும் நுட்பமான, மறைந்த குறை எதுவும் இருக்கக் கூடாது  –  தேர்ந்த ஹதீஸ் விமர்சகர்களால் (நுக்காத் அல்-ஹதீஸ்) மட்டுமே கண்டறியக்கூடியது.`, si: `සත්‍යතාව විනාශ කරන සියුම්, සැඟවුණු දෝෂයක් නොතිබිය යුතුය  –  එය සොයාගත හැක්කේ දක්ෂ හදීස් විචාරකයන්ට (නුක්කාද් අල්-හදීස්) පමණි.` },

  /* ── Classification of Hadiths ───────────────────────────── */
  'grades.heading': { en: `Classification of Hadiths`, ms: `Pengelasan Hadith`, tur: `Hadislerin Sınıflandırılması`, urd: `احادیث کی درجہ بندی`, ben: `হাদিসের শ্রেণিবিন্যাস`, fas: `طبقه‌بندی احادیث`, zh: `圣训的分级`, yue: `聖訓嘅分級`, ja: `ハディースの分類`, ru: `Классификация хадисов`, es: `Clasificación de los hadices`, ko: `하디스의 분류`, ta: `ஹதீஸ்களின் வகைப்பாடு`, si: `හදීස්වල වර්ගීකරණය` },
  'grades.sahih.definition': { en: `Authentic. The hadith is narrated by a trustworthy narrator from trustworthy narrators in an unbroken chain going back to the Prophet ﷺ, without shudhdudh (anomaly) and without 'illah (hidden defect).`, ms: `Sahih (Autentik). Hadith ini diriwayatkan oleh perawi yang boleh dipercayai daripada para perawi yang boleh dipercayai dalam rangkaian sanad yang tidak terputus sehingga kepada Nabi ﷺ, tanpa shudhudh (keganjilan) dan tanpa 'illah (kecacatan tersembunyi).`, tur: `Sahih (Otantik). Hadis, Peygamber ﷺ'e kadar kesintisiz bir zincirde güvenilir râvîlerden güvenilir bir râvî tarafından, şüzûz (aykırılık) ve illet (gizli kusur) olmadan rivayet edilmiştir.`, urd: `صحیح (مستند)۔ یہ حدیث ایک قابلِ اعتماد راوی نے قابلِ اعتماد راویوں سے ایک متصل سند میں نبی ﷺ تک، بغیر شذوذ (انوکھے پن) اور بغیر علت (پوشیدہ عیب) کے روایت کی ہے۔`, ben: `সহিহ (বিশুদ্ধ)। হাদিসটি একজন নির্ভরযোগ্য বর্ণনাকারী নির্ভরযোগ্য বর্ণনাকারীদের থেকে নবী ﷺ পর্যন্ত অবিচ্ছিন্ন সনদে, শুযূয (অসংগতি) ও ইল্লাহ (গোপন ত্রুটি) ছাড়া বর্ণনা করেছেন।`, fas: `صحیح (معتبر). این حدیث را راوی‌ای مورد اعتماد از راویانی مورد اعتماد، در سندی پیوسته تا پیامبر ﷺ، بدون شذوذ (ناهنجاری) و بدون علت (عیب پنهان) روایت کرده است.`, zh: `真实（萨希）。此圣训由一位可信传述者，从可信传述者传出，经一条不间断、上溯至先知ﷺ的传述链，无反常（舒祖兹）、无隐疾（伊莱）。`, yue: `真實（薩希）。此聖訓由一位可信傳述者，從可信傳述者傳出，經一條不間斷、上溯至先知ﷺ嘅傳述鏈，無反常（舒祖茲）、無隱疾（伊萊）。`, ja: `真正（サヒーフ）。このハディースは、信頼できる伝承者が信頼できる伝承者たちから、預言者ﷺにまで至る途切れぬ連鎖で、シュズーズ（変則）なく、イッラ（隠れた欠陥）なく伝えたものである。`, ru: `Достоверный (сахих). Хадис передан надёжным передатчиком от надёжных передатчиков в непрерывной цепи, восходящей к Пророку ﷺ, без шузуза (аномалии) и без илля (скрытого изъяна).`, es: `Auténtico (sahih). El hadiz es narrado por un narrador fiable, a partir de narradores fiables, en una cadena ininterrumpida que se remonta al Profeta ﷺ, sin shudhudh (anomalía) ni 'illah (defecto oculto).`, ko: `진정한(사히흐). 이 하디스는 신뢰할 만한 전승자가 신뢰할 만한 전승자들로부터, 예언자 ﷺ께까지 거슬러 올라가는 끊김 없는 사슬로, 슈두드(변칙)와 일라(숨은 결함) 없이 전한 것이다.`, ta: `ஸஹீஹ் (உண்மையானது). இந்த ஹதீஸ், ஒரு நம்பகமான அறிவிப்பாளர், நம்பகமான அறிவிப்பாளர்களிடமிருந்து, நபி ﷺ அவர்கள் வரை அறுபடாத சங்கிலியில், ஷுதூத் (முரண்) இன்றி, இல்லா (மறைந்த குறை) இன்றி அறிவித்தது.`, si: `සහීහ් (සත්‍ය). මෙම හදීසය විශ්වාසනීය වාර්තාකරුවෙකු, විශ්වාසනීය වාර්තාකරුවන්ගෙන්, නබි ﷺ තුමා දක්වා නොකැඩුණු දාමයක, ෂුදූද් (විෂමතාව) නැතිව, ඉල්ලා (සැඟවුණු දෝෂය) නැතිව වාර්තා කර ඇත.` },
  'grades.sahih.sub1.name': { en: `Sahih li-Dhatihi`, ms: `Sahih li-Dhatihi`, tur: `Sahîh li-Zâtihî`, urd: `صحیح لذاتہ`, ben: `সহিহ লিযাতিহি`, fas: `صحیح لذاته`, zh: `自身真实（Sahih li-Dhatihi）`, yue: `自身真實（Sahih li-Dhatihi）`, ja: `サヒーフ・リ＝ザーティヒ`, ru: `Сахих ли-затихи`, es: `Sahih li-Dhatihi`, ko: `사히흐 리다티히`, ta: `ஸஹீஹ் லிதாதிஹி`, si: `සහීහ් ලිදාතිහි` },
  'grades.sahih.sub1.detail': { en: `Authentic in itself  –  meets all five conditions with the highest degree of narrator reliability.`, ms: `Sahih dengan sendirinya  –  memenuhi kesemua lima syarat dengan darjah kebolehpercayaan perawi yang tertinggi.`, tur: `Kendiliğinden sahih  –  beş şartın hepsini en yüksek râvî güvenilirliğiyle karşılar.`, urd: `بذاتہ صحیح  –  راوی کی اعلیٰ ترین درجے کی وثاقت کے ساتھ پانچوں شرائط پوری کرتی ہے۔`, ben: `স্বতঃই সহিহ  –  বর্ণনাকারীর সর্বোচ্চ নির্ভরযোগ্যতাসহ পাঁচটি শর্তই পূরণ করে।`, fas: `به‌خودی‌خود صحیح  –  هر پنج شرط را با بالاترین درجه‌ی اعتماد راوی برآورده می‌کند.`, zh: `自身即为真实  –  以最高程度的传述者可信度满足全部五项条件。`, yue: `自身即為真實  –  以最高程度嘅傳述者可信度滿足全部五項條件。`, ja: `それ自体で真正  –  最高度の伝承者信頼性をもって五条件すべてを満たす。`, ru: `Достоверный сам по себе  –  отвечает всем пяти условиям при наивысшей надёжности передатчиков.`, es: `Auténtico en sí mismo  –  cumple las cinco condiciones con el más alto grado de fiabilidad de los narradores.`, ko: `그 자체로 진정함  –  최고 수준의 전승자 신뢰성으로 다섯 조건을 모두 충족.`, ta: `தன்னளவில் ஸஹீஹ்  –  அறிவிப்பாளர் நம்பகத்தன்மையின் உச்ச நிலையுடன் ஐந்து நிபந்தனைகளையும் பூர்த்தி செய்கிறது.`, si: `එය විසින්ම සහීහ්  –  ඉහළම වාර්තාකරු විශ්වාසනීයත්වයෙන් කොන්දේසි පහම සපුරයි.` },
  'grades.sahih.sub2.name': { en: `Sahih li-Ghayrihi`, ms: `Sahih li-Ghayrihi`, tur: `Sahîh li-Gayrihî`, urd: `صحیح لغیرہ`, ben: `সহিহ লিগাইরিহি`, fas: `صحیح لغیره`, zh: `因他而真实（Sahih li-Ghayrihi）`, yue: `因他而真實（Sahih li-Ghayrihi）`, ja: `サヒーフ・リ＝ガイリヒ`, ru: `Сахих ли-гайрихи`, es: `Sahih li-Ghayrihi`, ko: `사히흐 리가이리히`, ta: `ஸஹீஹ் லிகைரிஹி`, si: `සහීහ් ලිගයිරිහි` },
  'grades.sahih.sub2.detail': { en: `Elevated to sahih because of corroborating chains. Each individual chain is hasan, but together they raise the grade.`, ms: `Diangkat ke darjah sahih kerana rangkaian sanad yang menyokong. Setiap sanad secara individu adalah hasan, tetapi bersama-sama menaikkan darjahnya.`, tur: `Destekleyici zincirler sebebiyle sahih derecesine yükseltilmiş. Her bir zincir tek başına hasendir, ancak birlikte dereceyi yükseltir.`, urd: `تائیدی اسناد کی وجہ سے صحیح کے درجے تک بلند۔ ہر سند انفرادی طور پر حسن ہے، لیکن مل کر درجہ بلند کر دیتی ہیں۔`, ben: `সমর্থক সনদের কারণে সহিহ মর্যাদায় উন্নীত। প্রতিটি সনদ এককভাবে হাসান, কিন্তু একত্রে মর্যাদা বাড়ায়।`, fas: `به سبب اسناد پشتیبان به درجه‌ی صحیح ارتقا یافته. هر سند به‌تنهایی حسن است، اما با هم درجه را بالا می‌برند.`, zh: `因有佐证之传述链而升至真实级。每条链单独为良（哈桑），但合在一起便提升其等级。`, yue: `因有佐證之傳述鏈而升至真實級。每條鏈單獨為良（哈桑），但合埋一齊就提升其等級。`, ja: `補強する連鎖ゆえにサヒーフへ引き上げられる。各連鎖は単独ではハサンだが、合わさって格を上げる。`, ru: `Возведён до сахих благодаря подкрепляющим цепям. Каждая отдельная цепь  –  хасан, но вместе они повышают степень.`, es: `Elevado a sahih por cadenas corroborantes. Cada cadena por separado es hasan, pero juntas elevan el grado.`, ko: `보강하는 사슬들로 인해 사히흐로 격상됨. 개별 사슬은 하산이지만, 함께 등급을 높인다.`, ta: `உறுதிப்படுத்தும் சங்கிலிகளால் ஸஹீஹ் தரத்திற்கு உயர்த்தப்பட்டது. ஒவ்வொரு சங்கிலியும் தனித்தனியே ஹஸன், ஆனால் ஒன்றாக தரத்தை உயர்த்துகின்றன.`, si: `සහාය දාම නිසා සහීහ් මට්ටමට ඔසවා ඇත. එක් එක් දාමය වෙන වෙනම හසන් වුවද, එක්ව මට්ටම ඔසවයි.` },
  'grades.hasan.definition': { en: `Good. All conditions of sahih are met, but at least one narrator's accuracy (dabt) is slightly less precise than the highest standard. It is a valid source for Islamic rulings.`, ms: `Hasan (Baik). Semua syarat sahih dipenuhi, tetapi sekurang-kurangnya ketepatan (dabt) seorang perawi sedikit kurang tepat daripada piawaian tertinggi. Ia merupakan sumber yang sah untuk hukum-hakam Islam.`, tur: `Hasen (İyi). Sahihin bütün şartları karşılanır, ancak en az bir râvînin zabtı en yüksek standarttan biraz daha az hassastır. İslam hükümleri için geçerli bir kaynaktır.`, urd: `حسن (اچھا)۔ صحیح کی تمام شرائط پوری ہوتی ہیں، لیکن کم از کم ایک راوی کا ضبط اعلیٰ ترین معیار سے قدرے کم ہوتا ہے۔ یہ اسلامی احکام کے لیے ایک معتبر ماخذ ہے۔`, ben: `হাসান (উত্তম)। সহিহের সব শর্ত পূরণ হয়, তবে অন্তত একজন বর্ণনাকারীর নির্ভুলতা (যাবত) সর্বোচ্চ মানের চেয়ে সামান্য কম। এটি ইসলামি বিধানের জন্য একটি বৈধ উৎস।`, fas: `حسن (نیکو). همه‌ی شرایط صحیح برآورده می‌شود، اما ضبط دست‌کم یک راوی اندکی کمتر از بالاترین معیار است. منبعی معتبر برای احکام اسلامی است.`, zh: `良（哈桑）。具备真实级的一切条件，但至少有一位传述者的精准度（达卜特）略逊于最高标准。它是伊斯兰教法裁断的有效来源。`, yue: `良（哈桑）。具備真實級嘅一切條件，但至少有一位傳述者嘅精準度（達卜特）略遜於最高標準。佢係伊斯蘭教法裁斷嘅有效來源。`, ja: `良好（ハサン）。サヒーフのすべての条件を満たすが、少なくとも一人の伝承者の正確さ（ダブト）が最高基準よりわずかに劣る。イスラム法判断の有効な典拠である。`, ru: `Хороший (хасан). Все условия сахих соблюдены, но точность (дабт) по меньшей мере одного передатчика немного ниже наивысшего стандарта. Это действительный источник для исламских постановлений.`, es: `Bueno (hasan). Se cumplen todas las condiciones del sahih, pero la precisión (dabt) de al menos un narrador es algo menor que el estándar más alto. Es una fuente válida para los dictámenes islámicos.`, ko: `좋은(하산). 사히흐의 모든 조건이 충족되나, 적어도 한 전승자의 정확성(다브트)이 최고 기준보다 약간 떨어진다. 이슬람 판결의 유효한 전거이다.`, ta: `ஹஸன் (நல்லது). ஸஹீஹின் அனைத்து நிபந்தனைகளும் பூர்த்தியாகின்றன, ஆனால் குறைந்தது ஒரு அறிவிப்பாளரின் துல்லியம் (ளப்த்) உச்ச தரத்தைவிட சற்றுக் குறைவு. இது இஸ்லாமிய தீர்ப்புகளுக்கு செல்லுபடியான ஆதாரம்.`, si: `හසන් (හොඳ). සහීහ්හි සියලු කොන්දේසි සපුරයි, නමුත් අවම වශයෙන් එක් වාර්තාකරුවෙකුගේ නිරවද්‍යතාව (දබ්ත්) ඉහළම ප්‍රමිතියට වඩා තරමක් අඩුය. එය ඉස්ලාමීය තීන්දු සඳහා වලංගු මූලාශ්‍රයකි.` },
  'grades.hasan.sub1.name': { en: `Hasan li-Dhatihi`, ms: `Hasan li-Dhatihi`, tur: `Hasen li-Zâtihî`, urd: `حسن لذاتہ`, ben: `হাসান লিযাতিহি`, fas: `حسن لذاته`, zh: `自身良好（Hasan li-Dhatihi）`, yue: `自身良好（Hasan li-Dhatihi）`, ja: `ハサン・リ＝ザーティヒ`, ru: `Хасан ли-затихи`, es: `Hasan li-Dhatihi`, ko: `하산 리다티히`, ta: `ஹஸன் லிதாதிஹி`, si: `හසන් ලිදාතිහි` },
  'grades.hasan.sub1.detail': { en: `Good in itself  –  the chain contains a narrator of slightly lower precision than sahih standard.`, ms: `Hasan dengan sendirinya  –  rangkaian sanad mengandungi seorang perawi yang ketepatannya sedikit lebih rendah daripada piawaian sahih.`, tur: `Kendiliğinden hasen  –  zincirde, sahih standardından biraz daha az hassas bir râvî bulunur.`, urd: `بذاتہ حسن  –  سند میں ایک ایسا راوی ہے جس کا ضبط صحیح کے معیار سے قدرے کم ہے۔`, ben: `স্বতঃই হাসান  –  সনদে এমন একজন বর্ণনাকারী আছেন যাঁর নির্ভুলতা সহিহ মানের চেয়ে সামান্য কম।`, fas: `به‌خودی‌خود حسن  –  در سند راوی‌ای هست که دقتش اندکی کمتر از معیار صحیح است.`, zh: `自身即为良  –  传述链中含一位精准度略低于真实级标准的传述者。`, yue: `自身即為良  –  傳述鏈中含一位精準度略低於真實級標準嘅傳述者。`, ja: `それ自体で良好  –  連鎖に、サヒーフ基準よりわずかに正確さの劣る伝承者を含む。`, ru: `Хороший сам по себе  –  в цепи есть передатчик с точностью чуть ниже стандарта сахих.`, es: `Bueno en sí mismo  –  la cadena contiene un narrador de precisión algo inferior al estándar del sahih.`, ko: `그 자체로 좋음  –  사슬에 사히흐 기준보다 정확성이 약간 낮은 전승자가 포함됨.`, ta: `தன்னளவில் ஹஸன்  –  ஸஹீஹ் தரத்தைவிடச் சற்றுக் குறைந்த துல்லியம் கொண்ட ஒரு அறிவிப்பாளர் சங்கிலியில் உள்ளார்.`, si: `එය විසින්ම හසන්  –  සහීහ් ප්‍රමිතියට වඩා තරමක් අඩු නිරවද්‍යතාවක් ඇති වාර්තාකරුවෙකු දාමයේ ඇත.` },
  'grades.hasan.sub2.name': { en: `Hasan li-Ghayrihi`, ms: `Hasan li-Ghayrihi`, tur: `Hasen li-Gayrihî`, urd: `حسن لغیرہ`, ben: `হাসান লিগাইরিহি`, fas: `حسن لغیره`, zh: `因他而良好（Hasan li-Ghayrihi）`, yue: `因他而良好（Hasan li-Ghayrihi）`, ja: `ハサン・リ＝ガイリヒ`, ru: `Хасан ли-гайрихи`, es: `Hasan li-Ghayrihi`, ko: `하산 리가이리히`, ta: `ஹஸன் லிகைரிஹி`, si: `හසන් ලිගයිරිහි` },
  'grades.hasan.sub2.detail': { en: `Elevated from da'if to hasan by corroborating chains. The weakness is minor and the support compensates.`, ms: `Diangkat daripada da'if ke hasan oleh rangkaian sanad yang menyokong. Kelemahannya ringan dan sokongan itu menampungnya.`, tur: `Destekleyici zincirlerle zayıftan hasene yükseltilmiş. Zayıflık hafiftir ve destek bunu telafi eder.`, urd: `تائیدی اسناد کے ذریعے ضعیف سے حسن کے درجے تک بلند۔ کمزوری معمولی ہے اور تائید اس کی تلافی کر دیتی ہے۔`, ben: `সমর্থক সনদের মাধ্যমে যইফ থেকে হাসানে উন্নীত। দুর্বলতা সামান্য এবং সমর্থন তা পুষিয়ে দেয়।`, fas: `با اسناد پشتیبان از ضعیف به حسن ارتقا یافته. ضعف اندک است و پشتیبانی آن را جبران می‌کند.`, zh: `借佐证之传述链由弱（达伊夫）升至良。其弱处轻微，佐证足以弥补。`, yue: `借佐證之傳述鏈由弱（達伊夫）升至良。其弱處輕微，佐證足以彌補。`, ja: `補強する連鎖によりダイーフからハサンへ引き上げられる。弱さは軽微で、補強がそれを補う。`, ru: `Возведён из даифа в хасан подкрепляющими цепями. Слабость незначительна, и поддержка её восполняет.`, es: `Elevado de da'if a hasan por cadenas corroborantes. La debilidad es leve y el apoyo la compensa.`, ko: `보강하는 사슬들로 다이프에서 하산으로 격상됨. 약점이 경미하며 뒷받침이 이를 보완한다.`, ta: `உறுதிப்படுத்தும் சங்கிலிகளால் ளயீஃபிலிருந்து ஹஸனுக்கு உயர்த்தப்பட்டது. பலவீனம் சிறியது, ஆதரவு அதை ஈடுசெய்கிறது.`, si: `සහාය දාම මගින් දයීෆ් සිට හසන් දක්වා ඔසවා ඇත. දුර්වලතාව සුළුය, සහාය එය පියවයි.` },
  'grades.daif.definition': { en: `Weak. Fails to meet one or more of the five conditions for sahih. Cannot be used as primary evidence in fiqh, though some scholars permit using weak hadiths for encouragement (fada'il al-a'mal) under specific conditions.`, ms: `Da'if (Lemah). Gagal memenuhi satu atau lebih daripada lima syarat sahih. Tidak boleh digunakan sebagai dalil utama dalam fiqh, walaupun sesetengah ulama membenarkan penggunaan hadith lemah untuk galakan (fada'il al-a'mal) di bawah syarat-syarat tertentu.`, tur: `Zayıf. Sahihin beş şartından bir veya birkaçını karşılamaz. Fıkıhta birincil delil olarak kullanılamaz; ancak bazı âlimler belirli şartlar altında zayıf hadisleri teşvik (fezâilü'l-a'mâl) için kullanmaya izin verir.`, urd: `ضعیف (کمزور)۔ صحیح کی پانچ شرائط میں سے ایک یا زیادہ پوری نہیں کرتی۔ فقہ میں بنیادی دلیل کے طور پر استعمال نہیں ہو سکتی، اگرچہ بعض علماء مخصوص شرائط کے تحت ترغیب (فضائلِ اعمال) کے لیے ضعیف احادیث کے استعمال کی اجازت دیتے ہیں۔`, ben: `যইফ (দুর্বল)। সহিহের পাঁচ শর্তের এক বা একাধিক পূরণ করে না। ফিকহে প্রাথমিক দলিল হিসেবে ব্যবহার করা যায় না, যদিও কিছু আলেম নির্দিষ্ট শর্তে উৎসাহ (ফাজায়েলুল আমাল)-এর জন্য দুর্বল হাদিস ব্যবহারের অনুমতি দেন।`, fas: `ضعیف. یک یا چند شرط از پنج شرط صحیح را برآورده نمی‌کند. در فقه نمی‌توان آن را دلیل اصلی قرار داد، هرچند برخی علما با شرایطی خاص استفاده از احادیث ضعیف را برای ترغیب (فضائل الاعمال) جایز می‌دانند.`, zh: `弱（达伊夫）。未能满足真实级五项条件中的一项或多项。不可在教法中用作主要证据，但部分学者在特定条件下允许将弱圣训用于劝善（善功之德，法达伊勒）。`, yue: `弱（達伊夫）。未能滿足真實級五項條件中嘅一項或多項。唔可以喺教法中用作主要證據，但部分學者喺特定條件下允許將弱聖訓用於勸善（善功之德，法達伊勒）。`, ja: `弱い（ダイーフ）。サヒーフの五条件の一つ以上を満たさない。フィクフの第一義的証拠には使えないが、一部の学者は特定の条件の下で奨励（ファダーイル・アル＝アアマール）のために弱いハディースを用いることを許す。`, ru: `Слабый (даиф). Не отвечает одному или нескольким из пяти условий сахих. Не может служить первичным доводом в фикхе, хотя некоторые учёные при определённых условиях допускают использование слабых хадисов для побуждения к благому (фадаиль аль-а'маль).`, es: `Débil (da'if). No cumple una o más de las cinco condiciones del sahih. No puede usarse como prueba primaria en el fiqh, aunque algunos sabios permiten usar hadices débiles para el estímulo (fada'il al-a'mal) bajo condiciones específicas.`, ko: `약한(다이프). 사히흐의 다섯 조건 중 하나 이상을 충족하지 못함. 피크흐에서 일차적 증거로 쓸 수 없으나, 일부 학자는 특정 조건하에 권면(파다일 알아말)을 위해 약한 하디스 사용을 허용한다.`, ta: `ளயீஃப் (பலவீனம்). ஸஹீஹின் ஐந்து நிபந்தனைகளில் ஒன்று அல்லது அதற்கு மேற்பட்டவற்றைப் பூர்த்தி செய்யவில்லை. ஃபிக்ஹில் முதன்மை ஆதாரமாகப் பயன்படுத்த முடியாது, எனினும் சில அறிஞர்கள் குறிப்பிட்ட நிபந்தனைகளின் கீழ் ஊக்குவிப்புக்காக (ஃபளாயிலுல் அஃமால்) பலவீன ஹதீஸ்களைப் பயன்படுத்த அனுமதிக்கின்றனர்.`, si: `දයීෆ් (දුර්වල). සහීහ්හි කොන්දේසි පහෙන් එකක් හෝ කිහිපයක් සපුරාලන්නේ නැත. ෆික්හ්හි ප්‍රාථමික සාක්ෂියක් ලෙස භාවිත කළ නොහැක, එහෙත් ඇතැම් විද්වතුන් නිශ්චිත කොන්දේසි යටතේ දිරිගැන්වීම සඳහා (ෆළායිල් අල්-අඃමාල්) දුර්වල හදීස් භාවිතය අනුමත කරති.` },
  'grades.daif.sub1.name': { en: `Mawdu' (Fabricated)`, ms: `Mawdu' (Palsu)`, tur: `Mevzû (Uydurma)`, urd: `موضوع (من گھڑت)`, ben: `মাউযু (জাল)`, fas: `موضوع (جعلی)`, zh: `伪造（毛杜尔）`, yue: `偽造（毛杜爾）`, ja: `マウドゥー（捏造）`, ru: `Мауду (выдуманный)`, es: `Mawdu' (fabricado)`, ko: `마우두 (위조)`, ta: `மவ்ளூஉ (இட்டுக்கட்டப்பட்டது)`, si: `මව්දූඃ (ව්‍යාජ)` },
  'grades.daif.sub1.detail': { en: `The worst category  –  a hadith invented by a liar and falsely attributed to the Prophet ﷺ. Acting on a mawdu' hadith is impermissible.`, ms: `Kategori paling buruk  –  hadith yang direka oleh seorang pendusta dan dinisbahkan secara palsu kepada Nabi ﷺ. Beramal dengan hadith mawdu' adalah tidak dibenarkan.`, tur: `En kötü kategori  –  bir yalancının uydurup yalan yere Peygamber ﷺ'e nispet ettiği hadis. Mevzû bir hadisle amel etmek caiz değildir.`, urd: `سب سے بدترین قسم  –  ایک جھوٹے کی گھڑی ہوئی حدیث جو جھوٹ موٹ نبی ﷺ کی طرف منسوب کی گئی۔ موضوع حدیث پر عمل کرنا ناجائز ہے۔`, ben: `সবচেয়ে নিকৃষ্ট শ্রেণি  –  মিথ্যাবাদীর বানানো হাদিস যা মিথ্যাভাবে নবী ﷺ-এর প্রতি আরোপিত। মাউযু হাদিস অনুযায়ী আমল করা নাজায়েজ।`, fas: `بدترین دسته  –  حدیثی که دروغگویی آن را ساخته و به‌دروغ به پیامبر ﷺ نسبت داده است. عمل به حدیث موضوع جایز نیست.`, zh: `最劣等  –  由说谎者编造、伪托于先知ﷺ的圣训。依毛杜尔圣训行事是不被允许的。`, yue: `最劣等  –  由講大話者編造、偽託於先知ﷺ嘅聖訓。依毛杜爾聖訓行事係唔被允許嘅。`, ja: `最悪の区分  –  嘘つきが捏造し、偽って預言者ﷺに帰したハディース。マウドゥーのハディースに従って行うことは許されない。`, ru: `Худшая категория  –  хадис, выдуманный лжецом и ложно приписанный Пророку ﷺ. Поступать по хадису-мауду недопустимо.`, es: `La peor categoría  –  un hadiz inventado por un mentiroso y atribuido falsamente al Profeta ﷺ. Actuar conforme a un hadiz mawdu' es impermisible.`, ko: `최악의 범주  –  거짓말쟁이가 지어내어 예언자 ﷺ께 거짓으로 돌린 하디스. 마우두 하디스에 따라 행하는 것은 허용되지 않는다.`, ta: `மிக மோசமான வகை  –  ஒரு பொய்யரால் இட்டுக்கட்டப்பட்டு, பொய்யாக நபி ﷺ அவர்கள் மீது சாட்டப்பட்ட ஹதீஸ். மவ்ளூஉ ஹதீஸின்படி செயல்படுவது அனுமதிக்கப்படாதது.`, si: `නරකම ප්‍රවර්ගය  –  බොරුකාරයෙකු විසින් නිර්මාණය කර, බොරුවට නබි ﷺ තුමාට ආරෝපණය කළ හදීසයක්. මව්දූඃ හදීසයකට අනුව ක්‍රියා කිරීම අනුමත නැත.` },
  'grades.daif.sub2.name': { en: `Munkar (Denounced)`, ms: `Munkar (Dicela)`, tur: `Münker (Reddedilmiş)`, urd: `منکر (مردود)`, ben: `মুনকার (নিন্দিত)`, fas: `منکر (مردود)`, zh: `否定（蒙凯尔）`, yue: `否定（蒙凱爾）`, ja: `ムンカル（否認された）`, ru: `Мункар (отвергнутый)`, es: `Munkar (denunciado)`, ko: `문카르 (배척된)`, ta: `முன்கர் (கண்டிக்கப்பட்டது)`, si: `මුන්කර් (හෙළාදුටු)` },
  'grades.daif.sub2.detail': { en: `Narrated by a weak narrator in a way that contradicts what a reliable narrator has said.`, ms: `Diriwayatkan oleh perawi yang lemah dengan cara yang bertentangan dengan apa yang dikatakan oleh perawi yang boleh dipercayai.`, tur: `Zayıf bir râvî tarafından, güvenilir bir râvînin söylediğine aykırı biçimde rivayet edilmiş.`, urd: `ایک کمزور راوی نے ایسے انداز میں روایت کی جو ایک قابلِ اعتماد راوی کے بیان سے متصادم ہو۔`, ben: `একজন দুর্বল বর্ণনাকারী এমনভাবে বর্ণনা করেছেন যা একজন নির্ভরযোগ্য বর্ণনাকারীর বক্তব্যের বিরোধী।`, fas: `راوی‌ای ضعیف آن را به‌گونه‌ای روایت کرده که با گفته‌ی راوی‌ای معتمد در تضاد است.`, zh: `由一位弱传述者以与可信传述者所言相抵触的方式传述。`, yue: `由一位弱傳述者以與可信傳述者所言相抵觸嘅方式傳述。`, ja: `弱い伝承者が、信頼できる伝承者の述べたことに矛盾する形で伝えたもの。`, ru: `Передан слабым передатчиком так, что противоречит сказанному надёжным передатчиком.`, es: `Narrado por un narrador débil de un modo que contradice lo que ha dicho un narrador fiable.`, ko: `약한 전승자가 신뢰할 만한 전승자가 말한 바와 모순되게 전한 것.`, ta: `ஒரு பலவீன அறிவிப்பாளர், ஒரு நம்பகமான அறிவிப்பாளர் கூறியதற்கு முரணான முறையில் அறிவித்தது.`, si: `දුර්වල වාර්තාකරුවෙකු, විශ්වාසනීය වාර්තාකරුවෙකු පැවසූ දෙයට පටහැනි ලෙස වාර්තා කළ දෙයකි.` },

  /* ── Mutawatir and Ahad ──────────────────────────────────── */
  'tawatur.heading': { en: `Mutawatir and Ahad`, ms: `Mutawatir dan Ahad`, tur: `Mütevâtir ve Âhâd`, urd: `متواتر اور آحاد`, ben: `মুতাওয়াতির ও আহাদ`, fas: `متواتر و آحاد`, zh: `连续传述（多人传述）与单传`, yue: `連續傳述（多人傳述）與單傳`, ja: `ムタワーティルとアーハード`, ru: `Мутаватир и ахад`, es: `Mutawatir y ahad`, ko: `무타와티르와 아하드`, ta: `முதவாத்திர் மற்றும் ஆஹாத்`, si: `මුතවාතිර් සහ ආහාද්` },
  'tawatur.mutawatir.heading': { en: `Mutawatir`, ms: `Mutawatir`, tur: `Mütevâtir`, urd: `متواتر`, ben: `মুতাওয়াতির`, fas: `متواتر`, zh: `多人传述（Mutawatir）`, yue: `多人傳述（Mutawatir）`, ja: `ムタワーティル`, ru: `Мутаватир`, es: `Mutawatir`, ko: `무타와티르`, ta: `முதவாத்திர்`, si: `මුතවාතිර්` },
  'tawatur.mutawatir.body': { en: `Mass-transmitted: a hadith narrated by such a large number of people at every level of the chain that collusion or error is inconceivable. Mutawatir hadiths produce certain (qat'i) knowledge  –  scholars are unanimously bound by them. Example: "Whoever lies about me deliberately, let him take his seat in the Fire."  –  narrated by 80+ Companions.`, ms: `Diriwayatkan secara beramai-ramai: hadith yang diriwayatkan oleh sejumlah besar orang pada setiap peringkat sanad sehingga pakatan atau kesilapan tidak mungkin berlaku. Hadith mutawatir menghasilkan ilmu yang pasti (qat'i)  –  para ulama terikat dengannya secara sebulat suara. Contoh: "Sesiapa yang berdusta atasku dengan sengaja, hendaklah dia menyediakan tempat duduknya dalam Neraka."  –  diriwayatkan oleh 80+ Sahabat.`, tur: `Yaygın olarak nakledilen: zincirin her tabakasında o kadar çok kişi tarafından rivayet edilen hadis ki, anlaşma ya da hata düşünülemez. Mütevâtir hadisler kesin (kat'î) bilgi verir  –  âlimler bunlara ittifakla bağlıdır. Örnek: "Kim bana bilerek yalan isnat ederse, cehennemdeki yerine hazırlansın."  –  80'den fazla sahabe tarafından rivayet edilmiştir.`, urd: `کثرت سے نقل کردہ: ایسی حدیث جسے سند کے ہر طبقے پر اتنے بڑے گروہ نے روایت کیا کہ سازباز یا غلطی کا تصور ہی نہیں۔ متواتر احادیث یقینی (قطعی) علم پیدا کرتی ہیں  –  علماء بالاتفاق ان کے پابند ہیں۔ مثال: "جس نے جان بوجھ کر مجھ پر جھوٹ باندھا، وہ اپنا ٹھکانا جہنم میں بنا لے۔"  –  80 سے زائد صحابہ نے روایت کی۔`, ben: `ব্যাপকভাবে বর্ণিত: এমন হাদিস যা সনদের প্রতিটি স্তরে এত বিপুল সংখ্যক মানুষ বর্ণনা করেছেন যে যোগসাজশ বা ভুল কল্পনাতীত। মুতাওয়াতির হাদিস নিশ্চিত (কাতয়ি) জ্ঞান উৎপন্ন করে  –  আলেমগণ সর্বসম্মতভাবে এতে বাধ্য। উদাহরণ: "যে ইচ্ছাকৃতভাবে আমার নামে মিথ্যা বলে, সে যেন জাহান্নামে তার আসন গ্রহণ করে।"  –  ৮০+ সাহাবি বর্ণনা করেছেন।`, fas: `به‌طور گسترده نقل‌شده: حدیثی که در هر طبقه‌ی سند چنان شمار بزرگی آن را روایت کرده‌اند که تبانی یا خطا تصورناپذیر است. احادیث متواتر دانش یقینی (قطعی) پدید می‌آورند  –  علما به‌اتفاق بدان پایبندند. مثال: «هرکس عمداً بر من دروغ ببندد، جایگاه خود را در آتش آماده کند.»  –  بیش از ۸۰ صحابی آن را روایت کرده‌اند.`, zh: `大量传述：在传述链每一层级都有如此众多之人传述，以致串通或错误皆不可思议。连续传述的圣训产生确定（盖特义）的知识  –  学者一致受其约束。例："谁故意假借我之名撒谎，让他在火狱中自备座位。"  –  由八十多位圣门弟子传述。`, yue: `大量傳述：喺傳述鏈每一層級都有咁多人傳述，以致串通或錯誤皆不可思議。連續傳述嘅聖訓產生確定（蓋特義）嘅知識  –  學者一致受其約束。例："邊個故意假借我之名撒謊，就讓佢喺火獄中自備座位。"  –  由八十多位聖門弟子傳述。`, ja: `大量に伝えられたもの：連鎖のあらゆる段階で、結託や誤りが考えられないほど多数の人々によって伝えられたハディース。ムタワーティルのハディースは確定的（カトイー）な知識を生み  –  学者は一致してそれに従う。例：「故意に私について偽る者は、火獄に自らの座を占めるがよい。」  –  八十名を超える教友によって伝えられた。`, ru: `Массово переданный: хадис, переданный на каждом уровне цепи столь большим числом людей, что сговор или ошибка немыслимы. Хадисы-мутаватир дают достоверное (катʿи) знание  –  учёные единогласно связаны ими. Пример: «Кто намеренно лжёт на меня, пусть займёт своё место в Огне.»  –  передан более чем 80 сподвижниками.`, es: `Transmitido masivamente: un hadiz narrado por un número tan grande de personas en cada nivel de la cadena que la colusión o el error son inconcebibles. Los hadices mutawatir producen conocimiento cierto (qat'i)  –  los sabios están unánimemente obligados por ellos. Ejemplo: "Quien mienta sobre mí deliberadamente, que tome su asiento en el Fuego."  –  narrado por más de 80 Compañeros.`, ko: `대량 전승: 사슬의 모든 단계에서 담합이나 오류가 상상할 수 없을 만큼 많은 사람이 전한 하디스. 무타와티르 하디스는 확실한(카트이) 지식을 낳으며  –  학자들은 만장일치로 이에 구속된다. 예: "고의로 나에 대해 거짓말하는 자는 불지옥에 자기 자리를 잡게 하라."  –  80명 이상의 교우가 전함.`, ta: `பெருந்திரளாக அறிவிக்கப்பட்டது: சங்கிலியின் ஒவ்வொரு நிலையிலும் கூட்டுச்சதியோ பிழையோ கற்பனைக்கும் எட்டாத அளவுக்கு மிகப் பெரிய எண்ணிக்கையினரால் அறிவிக்கப்பட்ட ஹதீஸ். முதவாத்திர் ஹதீஸ்கள் உறுதியான (கத்ஈ) அறிவை உருவாக்குகின்றன  –  அறிஞர்கள் ஒருமனதாக அவற்றுக்குக் கட்டுப்பட்டவர்கள். எடுத்துக்காட்டு: "என் மீது வேண்டுமென்றே பொய் சொல்பவர், நரகத்தில் தம் இருக்கையை அமைத்துக்கொள்ளட்டும்."  –  80க்கும் மேற்பட்ட தோழர்களால் அறிவிக்கப்பட்டது.`, si: `පුළුල්ව සම්ප්‍රේෂණය වූ: දාමයේ සෑම මට්ටමකම, කුමන්ත්‍රණයක් හෝ වැරැද්දක් සිතාගත නොහැකි තරම් විශාල පිරිසක් වාර්තා කළ හදීසයක්. මුතවාතිර් හදීස් නිශ්චිත (කත්ඊ) දැනුමක් ඇති කරයි  –  විද්වතුන් ඒකමතිකව ඒවාට බැඳී සිටිති. උදාහරණය: "මා ගැන හිතාමතාම බොරු කියන්නා, නිරයේ තම අසුන සූදානම් කරගනීවා."  –  සහාබාවරුන් 80කට වැඩි පිරිසක් වාර්තා කළහ.` },
  'tawatur.ahad.heading': { en: `Khabar al-Ahad`, ms: `Khabar al-Ahad`, tur: `Haberü'l-Âhâd`, urd: `خبرِ آحاد`, ben: `খবরুল আহাদ`, fas: `خبر آحاد`, zh: `单传（Khabar al-Ahad）`, yue: `單傳（Khabar al-Ahad）`, ja: `ハバル・アル＝アーハード`, ru: `Хабар аль-ахад`, es: `Khabar al-Ahad`, ko: `카바르 알아하드`, ta: `கபருல் ஆஹாத்`, si: `ඛබර් අල්-ආහාද්` },
  'tawatur.ahad.body': { en: `Transmitted by one, two, or a small number of narrators at one or more levels. The vast majority of hadiths are ahad. They produce probable (zanni) knowledge, which is still binding in Islamic law if they are sahih or hasan  –  this is the position of the overwhelming majority of scholars.`, ms: `Diriwayatkan oleh satu, dua, atau sebilangan kecil perawi pada satu atau lebih peringkat. Majoriti besar hadith adalah ahad. Ia menghasilkan ilmu yang berkemungkinan (zanni), yang tetap mengikat dalam hukum Islam jika ia sahih atau hasan  –  inilah pendirian majoriti besar para ulama.`, tur: `Bir, iki ya da bir veya birkaç tabakada az sayıda râvî tarafından nakledilmiş. Hadislerin büyük çoğunluğu âhâddır. Zannî bilgi verir; sahih ya da hasen iseler İslam hukukunda yine bağlayıcıdır  –  bu, âlimlerin ezici çoğunluğunun görüşüdür.`, urd: `ایک، دو، یا چند راویوں نے ایک یا زیادہ طبقات پر روایت کی۔ احادیث کی بہت بڑی اکثریت آحاد ہے۔ یہ ظنی علم پیدا کرتی ہیں، جو اگر صحیح یا حسن ہوں تو اسلامی قانون میں پھر بھی واجب العمل ہیں  –  یہی علماء کی بھاری اکثریت کا مؤقف ہے۔`, ben: `এক, দুই, বা অল্পসংখ্যক বর্ণনাকারী এক বা একাধিক স্তরে বর্ণনা করেছেন। হাদিসের বিপুল সংখ্যাগরিষ্ঠই আহাদ। এগুলো সম্ভাব্য (যান্নি) জ্ঞান উৎপন্ন করে, যা সহিহ বা হাসান হলে ইসলামি আইনে তখনও মান্য  –  এটিই অধিকাংশ আলেমের অবস্থান।`, fas: `با یک، دو یا شمار اندکی از راویان در یک یا چند طبقه نقل شده. اکثریت قریب‌به‌اتفاق احادیث، آحاد است. این‌ها دانش ظنی پدید می‌آورند که اگر صحیح یا حسن باشند، در فقه همچنان لازم‌الاجراست  –  این دیدگاه اکثریت قاطع علماست.`, zh: `在一个或多个层级由一人、二人或少数传述者传述。绝大多数圣训属单传。它们产生或然（赞尼）的知识；若为真实或良，在伊斯兰教法中仍具约束力  –  此为绝大多数学者之立场。`, yue: `喺一個或多個層級由一人、二人或少數傳述者傳述。絕大多數聖訓屬單傳。佢哋產生或然（讚尼）嘅知識；若為真實或良，喺伊斯蘭教法中仍具約束力  –  此為絕大多數學者之立場。`, ja: `一つ以上の段階で、一人・二人、または少数の伝承者によって伝えられたもの。ハディースの圧倒的多数はアーハードである。蓋然的（ザンニー）な知識を生むが、サヒーフかハサンであればイスラム法で依然として拘束力を持つ  –  これが圧倒的多数の学者の立場である。`, ru: `Передан одним, двумя или небольшим числом передатчиков на одном или нескольких уровнях. Подавляющее большинство хадисов  –  ахад. Они дают вероятное (занни) знание, которое всё же обязательно в исламском праве, если они сахих или хасан  –  такова позиция подавляющего большинства учёных.`, es: `Transmitido por uno, dos o un pequeño número de narradores en uno o más niveles. La inmensa mayoría de los hadices son ahad. Producen conocimiento probable (zanni), que sigue siendo vinculante en la ley islámica si son sahih o hasan  –  esta es la postura de la abrumadora mayoría de los sabios.`, ko: `한 단계 이상에서 한 명, 두 명, 또는 소수의 전승자가 전한 것. 하디스의 절대다수가 아하드이다. 이는 개연적(잔니) 지식을 낳으며, 사히흐나 하산이면 이슬람법에서 여전히 구속력을 가진다  –  이것이 압도적 다수 학자의 입장이다.`, ta: `ஒன்று அல்லது அதற்கு மேற்பட்ட நிலைகளில் ஒருவர், இருவர், அல்லது சிறிய எண்ணிக்கையிலான அறிவிப்பாளர்களால் அறிவிக்கப்பட்டது. ஹதீஸ்களில் பெரும்பான்மை ஆஹாத். இவை சாத்தியமான (ழன்னி) அறிவை உருவாக்குகின்றன, அவை ஸஹீஹ் அல்லது ஹஸன் எனில் இஸ்லாமிய சட்டத்தில் இன்னும் கட்டுப்படுத்தும்  –  இதுவே பெரும்பான்மை அறிஞர்களின் நிலைப்பாடு.`, si: `එක් හෝ වැඩි මට්ටම්වල එක්, දෙක, හෝ සුළු වාර්තාකරුවන් පිරිසක් විසින් සම්ප්‍රේෂණය විය. හදීස්වලින් අතිමහත් බහුතරය ආහාද් වේ. ඒවා සම්භාව්‍ය (ළන්නී) දැනුමක් ඇති කරයි, ඒවා සහීහ් හෝ හසන් නම් ඉස්ලාමීය නීතියේ තවමත් බැඳීමක් වේ  –  මෙය විද්වතුන්ගේ අතිබහුතරයේ ස්ථාවරයයි.` },

  /* ── The Six Books ───────────────────────────────────────── */
  'sixbooks.heading': { en: `The Six Books (Kutub al-Sittah)`, ms: `Enam Kitab (Kutub al-Sittah)`, tur: `Altı Kitap (Kütüb-i Sitte)`, urd: `چھ کتب (کتبِ ستہ)`, ben: `ছয় কিতাব (কুতুবুস সিত্তাহ)`, fas: `شش کتاب (کتب سته)`, zh: `六大圣训集（库图卜·西塔）`, yue: `六大聖訓集（庫圖卜·西塔）`, ja: `六書（クトゥブ・アッ＝シッタ）`, ru: `Шесть книг (Кутуб ас-ситта)`, es: `Los Seis Libros (Kutub al-Sittah)`, ko: `여섯 책 (쿠툽 알시타)`, ta: `ஆறு நூல்கள் (குதுபுஸ் ஸித்தா)`, si: `පොත් හය (කුතුබ් අස්-සිත්තා)` },
  'sixbooks.1.count': { en: `7,563 hadiths (including repetitions)`, ms: `7,563 hadith (termasuk pengulangan)`, tur: `7.563 hadis (tekrarlar dâhil)`, urd: `7,563 احادیث (تکرار سمیت)`, ben: `৭,৫৬৩টি হাদিস (পুনরাবৃত্তিসহ)`, fas: `۷٬۵۶۳ حدیث (با تکرارها)`, zh: `7,563段圣训（含重复）`, yue: `7,563段聖訓（含重複）`, ja: `7,563のハディース（重複を含む）`, ru: `7563 хадиса (с повторами)`, es: `7.563 hadices (con repeticiones)`, ko: `7,563개 하디스 (반복 포함)`, ta: `7,563 ஹதீஸ்கள் (மறுபதிப்புகள் உட்பட)`, si: `හදීස් 7,563ක් (පුනරාවර්තන සහිතව)` },
  'sixbooks.1.note': { en: `The most authentic book after the Quran in the opinion of the majority of scholars. Al-Bukhari reportedly reviewed 600,000 hadiths over 16 years and selected only those meeting his rigorous criteria.`, ms: `Kitab paling sahih selepas al-Quran menurut pendapat majoriti ulama. Al-Bukhari dilaporkan menyemak 600,000 hadith selama 16 tahun dan memilih hanya yang memenuhi kriteria ketatnya.`, tur: `Âlimlerin çoğunluğunun görüşüne göre Kur'an'dan sonra en sahih kitap. Buhârî'nin 16 yıl boyunca 600.000 hadis incelediği ve yalnızca titiz ölçütlerini karşılayanları seçtiği nakledilir.`, urd: `اکثر علماء کی رائے میں قرآن کے بعد سب سے صحیح کتاب۔ بیان کیا جاتا ہے کہ بخاری نے 16 سال میں 600,000 احادیث کا جائزہ لیا اور صرف انہی کو منتخب کیا جو ان کے سخت معیار پر پورا اترتی تھیں۔`, ben: `অধিকাংশ আলেমের মতে কুরআনের পর সবচেয়ে বিশুদ্ধ গ্রন্থ। বর্ণিত আছে যে বুখারি ১৬ বছরে ৬,০০,০০০ হাদিস পর্যালোচনা করেন এবং কেবল তাঁর কঠোর মানদণ্ড পূরণকারীগুলো নির্বাচন করেন।`, fas: `به نظر اکثر علما، صحیح‌ترین کتاب پس از قرآن. گفته می‌شود بخاری در طول ۱۶ سال ۶۰۰٬۰۰۰ حدیث را بررسی کرد و تنها آن‌هایی را که معیارهای سخت‌گیرانه‌اش را برآورده می‌کردند برگزید.`, zh: `多数学者认为是《古兰经》之后最真实的典籍。据传布哈里历时16年审阅60万段圣训，仅选取符合其严格标准者。`, yue: `多數學者認為係《古蘭經》之後最真實嘅典籍。據傳布哈里歷時16年審閱60萬段聖訓，只選取符合其嚴格標準者。`, ja: `多数の学者の見解では、クルアーンに次いで最も真正な書。ブハーリーは16年かけて60万のハディースを精査し、その厳格な基準を満たすものだけを選んだと伝えられる。`, ru: `По мнению большинства учёных, самая достоверная книга после Корана. Сообщается, что аль-Бухари за 16 лет рассмотрел 600 000 хадисов и отобрал лишь те, что отвечали его строгим критериям.`, es: `El libro más auténtico después del Corán en opinión de la mayoría de los sabios. Se dice que al-Bukhari revisó 600.000 hadices a lo largo de 16 años y seleccionó solo los que cumplían sus rigurosos criterios.`, ko: `대다수 학자의 견해로 꾸란 다음으로 가장 진정한 책. 부카리는 16년에 걸쳐 60만 개의 하디스를 검토하여 그의 엄격한 기준을 충족하는 것만 선별했다고 전해진다.`, ta: `பெரும்பான்மை அறிஞர்களின் கருத்துப்படி குர்ஆனுக்குப் பின் மிகவும் உண்மையான நூல். புகாரி 16 ஆண்டுகளில் 6,00,000 ஹதீஸ்களை ஆய்வுசெய்து, தம் கடுமையான தரநிலையைப் பூர்த்தி செய்தவற்றை மட்டுமே தேர்ந்தெடுத்தார் எனக் கூறப்படுகிறது.`, si: `බහුතර විද්වතුන්ගේ මතය අනුව කුර්ආනයෙන් පසු වඩාත්ම සත්‍ය ග්‍රන්ථය. බුහාරි වසර 16ක් පුරා හදීස් 600,000ක් සමාලෝචනය කර, ඔහුගේ දැඩි නිර්ණායක සපුරාලූ ඒවා පමණක් තෝරාගත් බව වාර්තා වේ.` },
  'sixbooks.2.count': { en: `~7,500 hadiths`, ms: `~7,500 hadith`, tur: `~7.500 hadis`, urd: `~7,500 احادیث`, ben: `~৭,৫০০টি হাদিস`, fas: `حدود ۷٬۵۰۰ حدیث`, zh: `约7,500段圣训`, yue: `約7,500段聖訓`, ja: `約7,500のハディース`, ru: `~7500 хадисов`, es: `~7.500 hadices`, ko: `약 7,500개 하디스`, ta: `~7,500 ஹதீஸ்கள்`, si: `හදීස් 7,500ක් පමණ` },
  'sixbooks.2.note': { en: `Second only to Bukhari in authority. Praised for its superior arrangement  –  Muslim gathers all chains for a single hadith in one place, whereas Bukhari distributes them across chapters.`, ms: `Kedua selepas Bukhari dari segi kewibawaan. Dipuji kerana susunannya yang unggul  –  Muslim menghimpunkan semua sanad bagi satu hadith di satu tempat, manakala Bukhari menyebarkannya merentas bab.`, tur: `Otorite bakımından yalnızca Buhârî'den sonra gelir. Üstün tertibi sebebiyle övülür  –  Müslim, tek bir hadisin bütün isnadlarını tek bir yerde toplar, Buhârî ise onları bablara dağıtır.`, urd: `اختیار میں بخاری کے بعد دوسرے نمبر پر۔ اپنی عمدہ ترتیب کے لیے سراہی گئی  –  مسلم ایک ہی حدیث کی تمام اسناد ایک جگہ جمع کرتے ہیں، جبکہ بخاری انہیں مختلف ابواب میں بکھیر دیتے ہیں۔`, ben: `কর্তৃত্বে কেবল বুখারির পরেই। এর উন্নত বিন্যাসের জন্য প্রশংসিত  –  মুসলিম একটি হাদিসের সব সনদ এক জায়গায় একত্র করেন, যেখানে বুখারি সেগুলো বিভিন্ন অধ্যায়ে ছড়িয়ে দেন।`, fas: `از نظر اعتبار تنها پس از بخاری. به سبب چینش برترش ستوده شده  –  مسلم همه‌ی اسناد یک حدیث را در یک جا گرد می‌آورد، حال آنکه بخاری آن‌ها را در باب‌های مختلف پراکنده می‌کند.`, zh: `权威性仅次于布哈里。因其编排卓越而受赞誉  –  穆斯林将一段圣训的所有传述链汇于一处，而布哈里则分散于各章。`, yue: `權威性僅次於布哈里。因其編排卓越而受讚譽  –  穆斯林將一段聖訓嘅所有傳述鏈匯於一處，而布哈里則分散於各章。`, ja: `権威においてブハーリーに次ぐ。その優れた配列ゆえに称えられる  –  ムスリムは一つのハディースのすべての連鎖を一か所に集めるが、ブハーリーは各章に分散させる。`, ru: `По авторитету уступает лишь Бухари. Хвалим за превосходное расположение  –  Муслим собирает все цепи одного хадиса в одном месте, тогда как Бухари распределяет их по главам.`, es: `Solo superado por Bukhari en autoridad. Elogiado por su disposición superior  –  Muslim reúne todas las cadenas de un solo hadiz en un lugar, mientras que Bukhari las distribuye por capítulos.`, ko: `권위에서 부카리 다음이다. 뛰어난 배열로 칭송받는다  –  무슬림은 한 하디스의 모든 사슬을 한곳에 모으는 반면, 부카리는 여러 장에 분산시킨다.`, ta: `அதிகாரத்தில் புகாரிக்கு அடுத்தபடியாக மட்டுமே. அதன் சிறந்த அமைப்புக்காகப் புகழப்படுகிறது  –  முஸ்லிம் ஒரே ஹதீஸுக்கான அனைத்து சங்கிலிகளையும் ஒரே இடத்தில் தொகுக்கிறார், புகாரி அவற்றை அத்தியாயங்களில் பரப்புகிறார்.`, si: `අධිකාරියෙන් බුහාරිට පමණක් දෙවැනියි. එහි උසස් සැකැස්ම නිසා ප්‍රශංසා ලබයි  –  මුස්ලිම් එක් හදීසයක සියලු දාම එක් තැනක එක්රැස් කරයි, බුහාරි ඒවා පරිච්ඡේද හරහා බෙදා හරියි.` },
  'sixbooks.3.count': { en: `5,274 hadiths`, ms: `5,274 hadith`, tur: `5.274 hadis`, urd: `5,274 احادیث`, ben: `৫,২৭৪টি হাদিস`, fas: `۵٬۲۷۴ حدیث`, zh: `5,274段圣训`, yue: `5,274段聖訓`, ja: `5,274のハディース`, ru: `5274 хадиса`, es: `5.274 hadices`, ko: `5,274개 하디스`, ta: `5,274 ஹதீஸ்கள்`, si: `හදීස් 5,274ක්` },
  'sixbooks.3.note': { en: `Focused on fiqh (legal rulings). Abu Dawud reportedly selected from 500,000 hadiths. He noted weak hadiths when no stronger narration on that legal issue existed.`, ms: `Tertumpu pada fiqh (hukum-hakam). Abu Dawud dilaporkan memilih daripada 500,000 hadith. Beliau mencatatkan hadith lemah apabila tiada riwayat yang lebih kuat mengenai isu hukum itu.`, tur: `Fıkha (hükümlere) odaklanır. Ebû Dâvûd'un 500.000 hadis arasından seçtiği nakledilir. O hukukî meselede daha güçlü bir rivayet bulunmadığında zayıf hadisleri kaydetti.`, urd: `فقہ (احکام) پر مرکوز۔ بیان کیا جاتا ہے کہ ابو داؤد نے 500,000 احادیث میں سے انتخاب کیا۔ جب اس فقہی مسئلے پر کوئی زیادہ قوی روایت موجود نہ ہوتی تو وہ ضعیف احادیث درج کر دیتے۔`, ben: `ফিকহ (বিধান) কেন্দ্রিক। বর্ণিত আছে আবু দাউদ ৫,০০,০০০ হাদিস থেকে নির্বাচন করেন। সেই আইনি বিষয়ে শক্তিশালী কোনো বর্ণনা না থাকলে তিনি দুর্বল হাদিস উল্লেখ করতেন।`, fas: `متمرکز بر فقه (احکام). گفته می‌شود ابوداود از میان ۵۰۰٬۰۰۰ حدیث برگزید. هرگاه در آن مسئله‌ی فقهی روایتی قوی‌تر وجود نداشت، احادیث ضعیف را یادداشت می‌کرد.`, zh: `专注于教法（律例）。据传艾布·达伍德从50万段圣训中选取。当某法律问题无更强传述时，他会注明弱圣训。`, yue: `專注於教法（律例）。據傳艾布·達伍德從50萬段聖訓中選取。當某法律問題無更強傳述時，佢會註明弱聖訓。`, ja: `フィクフ（法規定）に重点を置く。アブー・ダーウードは50万のハディースから選んだと伝えられる。その法的問題により強い伝承がない場合には、弱いハディースを注記した。`, ru: `Сосредоточен на фикхе (правовых постановлениях). Сообщается, что Абу Дауд отбирал из 500 000 хадисов. Он отмечал слабые хадисы, когда по данному правовому вопросу не было более сильного предания.`, es: `Centrado en el fiqh (dictámenes legales). Se dice que Abu Dawud seleccionó de 500.000 hadices. Anotaba los hadices débiles cuando no existía una narración más fuerte sobre esa cuestión legal.`, ko: `피크흐(법적 판결)에 집중함. 아부 다우드는 50만 개의 하디스에서 선별했다고 전해진다. 해당 법적 문제에 더 강한 전승이 없을 때 그는 약한 하디스를 표시했다.`, ta: `ஃபிக்ஹ் (சட்டத் தீர்ப்புகள்) மீது கவனம் செலுத்தியது. அபூ தாவூத் 5,00,000 ஹதீஸ்களிலிருந்து தேர்ந்தெடுத்தார் எனக் கூறப்படுகிறது. அந்தச் சட்ட விஷயத்தில் வலுவான அறிவிப்பு இல்லாதபோது அவர் பலவீன ஹதீஸ்களைக் குறித்து வைத்தார்.`, si: `ෆික්හ් (නීති තීන්දු) කෙරෙහි අවධානය යොමු කරයි. අබූ දාවූද් හදීස් 500,000කින් තෝරාගත් බව වාර්තා වේ. එම නීති ප්‍රශ්නය පිළිබඳ වඩා ශක්තිමත් වාර්තාවක් නොතිබූ විට ඔහු දුර්වල හදීස් සටහන් කළේය.` },

  'sixbooks.4.count': { en: `3,956 hadiths`, ms: `3,956 hadith`, tur: `3.956 hadis`, urd: `3,956 احادیث`, ben: `৩,৯৫৬টি হাদিস`, fas: `۳٬۹۵۶ حدیث`, zh: `3,956段圣训`, yue: `3,956段聖訓`, ja: `3,956のハディース`, ru: `3956 хадисов`, es: `3.956 hadices`, ko: `3,956개 하디스`, ta: `3,956 ஹதீஸ்கள்`, si: `හදීස් 3,956ක්` },
  'sixbooks.4.note': { en: `Unique for noting after each hadith whether it is sahih, hasan, or da'if, and recording the opinions of early scholars on each ruling. A valuable encyclopaedia of fiqh and hadith grading.`, ms: `Unik kerana mencatatkan selepas setiap hadith sama ada ia sahih, hasan, atau da'if, dan merekodkan pendapat ulama awal mengenai setiap hukum. Sebuah ensiklopedia berharga tentang fiqh dan penggredan hadith.`, tur: `Her hadisten sonra onun sahih, hasen ya da zayıf olduğunu belirtmesi ve her hüküm hakkında ilk dönem âlimlerinin görüşlerini kaydetmesiyle benzersizdir. Fıkıh ve hadis derecelendirmesinin değerli bir ansiklopedisidir.`, urd: `ہر حدیث کے بعد یہ بیان کرنے میں منفرد کہ آیا وہ صحیح، حسن، یا ضعیف ہے، اور ہر حکم پر متقدمین علماء کی آراء درج کرنے میں۔ فقہ اور درجہ بندیِ حدیث کا ایک قیمتی دائرۃ المعارف۔`, ben: `প্রতিটি হাদিসের পরে তা সহিহ, হাসান, না যইফ তা উল্লেখ করা এবং প্রতিটি বিধানে প্রাচীন আলেমদের মতামত লিপিবদ্ধ করার জন্য অনন্য। ফিকহ ও হাদিস শ্রেণিকরণের এক মূল্যবান বিশ্বকোষ।`, fas: `در یادداشت کردن اینکه هر حدیث پس از خود صحیح، حسن یا ضعیف است، و ثبت آرای علمای متقدم درباره‌ی هر حکم، بی‌نظیر است. دایرةالمعارفی ارزشمند در فقه و درجه‌بندی حدیث.`, zh: `其独到之处在于每段圣训之后注明其为真实、良或弱，并记录早期学者对各裁断的意见。是教法与圣训分级的宝贵百科。`, yue: `其獨到之處在於每段聖訓之後註明其為真實、良或弱，並記錄早期學者對各裁斷嘅意見。係教法與聖訓分級嘅寶貴百科。`, ja: `各ハディースの後にそれがサヒーフ・ハサン・ダイーフのいずれかを記し、各判断についての初期の学者の見解を記録する点で独特である。フィクフとハディース格付けの貴重な百科である。`, ru: `Уникален тем, что после каждого хадиса отмечает, сахих ли он, хасан или даиф, и фиксирует мнения ранних учёных по каждому постановлению. Ценная энциклопедия фикха и градации хадисов.`, es: `Único por anotar tras cada hadiz si es sahih, hasan o da'if, y por registrar las opiniones de los primeros sabios sobre cada dictamen. Una valiosa enciclopedia de fiqh y gradación del hadiz.`, ko: `각 하디스 뒤에 그것이 사히흐, 하산, 다이프인지 표시하고, 각 판결에 대한 초기 학자들의 견해를 기록한 점에서 독특하다. 피크흐와 하디스 등급의 귀중한 백과이다.`, ta: `ஒவ்வொரு ஹதீஸுக்குப் பின்னும் அது ஸஹீஹா, ஹஸனா, ளயீஃபா எனக் குறிப்பதிலும், ஒவ்வொரு தீர்ப்பிலும் முற்கால அறிஞர்களின் கருத்துகளைப் பதிவுசெய்வதிலும் தனித்துவமானது. ஃபிக்ஹ் மற்றும் ஹதீஸ் தரப்படுத்தலின் மதிப்புமிக்க கலைக்களஞ்சியம்.`, si: `සෑම හදීසයකට පසුව එය සහීහ්ද, හසන්ද, දයීෆ්ද යන්න සටහන් කිරීමෙන් සහ සෑම තීන්දුවක් පිළිබඳ මුල් කාලීන විද්වතුන්ගේ අදහස් වාර්තා කිරීමෙන් අද්විතීයයි. ෆික්හ් සහ හදීස් වර්ගීකරණයේ වටිනා විශ්වකෝෂයකි.` },
  'sixbooks.5.count': { en: `~5,761 hadiths`, ms: `~5,761 hadith`, tur: `~5.761 hadis`, urd: `~5,761 احادیث`, ben: `~৫,৭৬১টি হাদিস`, fas: `حدود ۵٬۷۶۱ حدیث`, zh: `约5,761段圣训`, yue: `約5,761段聖訓`, ja: `約5,761のハディース`, ru: `~5761 хадис`, es: `~5.761 hadices`, ko: `약 5,761개 하디스`, ta: `~5,761 ஹதீஸ்கள்`, si: `හදීස් 5,761ක් පමණ` },
  'sixbooks.5.note': { en: `Al-Nasa'i had the most demanding standards for narrator criticism among the Kutub al-Sittah authors. His conditions for accepting narrators were stricter than Bukhari in some opinions.`, ms: `Al-Nasa'i mempunyai piawaian paling ketat untuk kritik perawi dalam kalangan pengarang Kutub al-Sittah. Syaratnya untuk menerima perawi adalah lebih ketat daripada Bukhari menurut sesetengah pendapat.`, tur: `Nesâî, Kütüb-i Sitte yazarları arasında râvî tenkidinde en zorlu ölçütlere sahipti. Râvîleri kabul şartları, bazı görüşlere göre Buhârî'den daha katıydı.`, urd: `النسائی کے ہاں کتبِ ستہ کے مصنفین میں راوی پر تنقید کے سب سے سخت معیار تھے۔ بعض آراء کے مطابق راویوں کو قبول کرنے کی ان کی شرائط بخاری سے بھی سخت تھیں۔`, ben: `কুতুবুস সিত্তাহর লেখকদের মধ্যে নাসায়ির বর্ণনাকারী সমালোচনার মানদণ্ড ছিল সবচেয়ে কঠোর। কিছু মতে বর্ণনাকারী গ্রহণে তাঁর শর্ত বুখারির চেয়েও কঠোর ছিল।`, fas: `نسائی در میان نویسندگان کتب سته سخت‌گیرانه‌ترین معیارها را در نقد راوی داشت. به‌گفته‌ی برخی، شرایط او برای پذیرش راویان از بخاری هم سخت‌تر بود.`, zh: `在六大圣训集作者中，奈萨仪对传述者评判的标准最为严苛。据某些意见，他接纳传述者的条件比布哈里更严。`, yue: `喺六大聖訓集作者中，奈薩儀對傳述者評判嘅標準最為嚴苛。據某啲意見，佢接納傳述者嘅條件比布哈里更嚴。`, ja: `六書の著者の中で、ナサーイーは伝承者批判において最も厳しい基準を持っていた。伝承者を受け入れる彼の条件は、一部の見解ではブハーリーより厳格であった。`, ru: `Среди авторов «Кутуб ас-ситта» у ан-Насаи были самые требовательные критерии критики передатчиков. По некоторым мнениям, его условия принятия передатчиков были строже, чем у Бухари.`, es: `Al-Nasa'i tenía los criterios más exigentes de crítica de narradores entre los autores de los Kutub al-Sittah. Sus condiciones para aceptar narradores eran, en algunas opiniones, más estrictas que las de Bukhari.`, ko: `쿠툽 알시타 저자들 중 나사이는 전승자 비평에서 가장 까다로운 기준을 지녔다. 일부 견해에 따르면 전승자를 받아들이는 그의 조건은 부카리보다 엄격했다.`, ta: `குதுபுஸ் ஸித்தா ஆசிரியர்களில் நஸாயீ அறிவிப்பாளர் விமர்சனத்தில் மிகக் கடுமையான தரநிலைகளைக் கொண்டிருந்தார். அறிவிப்பாளர்களை ஏற்பதற்கான அவரது நிபந்தனைகள் சில கருத்துகளின்படி புகாரியைவிடக் கடுமையானவை.`, si: `කුතුබ් අස්-සිත්තා කතුවරුන් අතර, වාර්තාකරු විවේචනය සඳහා නසායීට වඩාත්ම දැඩි ප්‍රමිතීන් තිබුණි. වාර්තාකරුවන් පිළිගැනීමේ ඔහුගේ කොන්දේසි ඇතැම් මත අනුව බුහාරිට වඩා දැඩි විය.` },
  'sixbooks.6.count': { en: `4,341 hadiths`, ms: `4,341 hadith`, tur: `4.341 hadis`, urd: `4,341 احادیث`, ben: `৪,৩৪১টি হাদিস`, fas: `۴٬۳۴۱ حدیث`, zh: `4,341段圣训`, yue: `4,341段聖訓`, ja: `4,341のハディース`, ru: `4341 хадис`, es: `4.341 hadices`, ko: `4,341개 하디스`, ta: `4,341 ஹதீஸ்கள்`, si: `හදීස් 4,341ක්` },
  'sixbooks.6.note': { en: `Contains unique hadiths not found in the other five books. Some of these are weak; scholars advise checking grades carefully. Nevertheless the work is indispensable for its coverage.`, ms: `Mengandungi hadith unik yang tidak ditemui dalam lima kitab yang lain. Sebahagian daripadanya lemah; para ulama menasihatkan agar menyemak gred dengan teliti. Namun begitu, karya ini amat diperlukan kerana liputannya.`, tur: `Diğer beş kitapta bulunmayan kendine has hadisler içerir. Bunların bazısı zayıftır; âlimler dereceleri dikkatle kontrol etmeyi tavsiye eder. Yine de eser, kapsamı bakımından vazgeçilmezdir.`, urd: `ایسی منفرد احادیث پر مشتمل ہے جو دیگر پانچ کتب میں نہیں ملتیں۔ ان میں سے کچھ ضعیف ہیں؛ علماء درجات کو احتیاط سے جانچنے کی نصیحت کرتے ہیں۔ تاہم یہ کام اپنی جامعیت کے سبب ناگزیر ہے۔`, ben: `অন্য পাঁচ গ্রন্থে নেই এমন অনন্য হাদিস ধারণ করে। এর কিছু দুর্বল; আলেমগণ মর্যাদা সতর্কভাবে যাচাইয়ের পরামর্শ দেন। তবুও এর ব্যাপ্তির জন্য গ্রন্থটি অপরিহার্য।`, fas: `احادیثی منحصربه‌فرد دارد که در پنج کتاب دیگر یافت نمی‌شود. برخی از این‌ها ضعیف‌اند؛ علما توصیه می‌کنند درجات با دقت بررسی شود. با این حال، این اثر به سبب گستردگی‌اش ضروری است.`, zh: `含有其他五书所无的独有圣训。其中部分为弱；学者建议仔细核查等级。尽管如此，此书因其涵盖之广而不可或缺。`, yue: `含有其他五書所無嘅獨有聖訓。其中部分為弱；學者建議仔細核查等級。儘管如此，此書因其涵蓋之廣而不可或缺。`, ja: `他の五書にない独自のハディースを含む。その一部は弱い。学者は格付けを慎重に確認するよう勧める。それでもこの著作は、その網羅性ゆえに欠かせない。`, ru: `Содержит уникальные хадисы, отсутствующие в остальных пяти книгах. Некоторые из них слабые; учёные советуют тщательно проверять степени. Тем не менее труд незаменим благодаря охвату.`, es: `Contiene hadices únicos que no se encuentran en los otros cinco libros. Algunos son débiles; los sabios aconsejan comprobar los grados con cuidado. No obstante, la obra es indispensable por su cobertura.`, ko: `다른 다섯 책에 없는 고유한 하디스를 담고 있다. 그중 일부는 약하다; 학자들은 등급을 신중히 확인할 것을 권한다. 그럼에도 이 책은 그 포괄성 때문에 없어서는 안 된다.`, ta: `மற்ற ஐந்து நூல்களில் இல்லாத தனித்துவமான ஹதீஸ்களைக் கொண்டுள்ளது. இவற்றில் சில பலவீனமானவை; அறிஞர்கள் தரங்களைக் கவனமாகச் சரிபார்க்க அறிவுறுத்துகின்றனர். இருப்பினும் இந்நூல் அதன் பரப்பின் காரணமாக இன்றியமையாதது.`, si: `අනෙක් පොත් පහේ නොමැති අද්විතීය හදීස් අඩංගුය. මේවායින් සමහරක් දුර්වලය; විද්වතුන් මට්ටම් ප්‍රවේශමෙන් පරීක්ෂා කරන ලෙස උපදෙස් දෙති. එහෙත් එහි ආවරණය නිසා මෙම කෘතිය අත්‍යවශ්‍යය.` },

  /* ── The Great Hadith Scholars ───────────────────────────── */
  'scholars.heading': { en: `The Great Hadith Scholars`, ms: `Para Ulama Hadith yang Agung`, tur: `Büyük Hadis Âlimleri`, urd: `عظیم محدثین`, ben: `মহান হাদিসবিদগণ`, fas: `محدثان بزرگ`, zh: `伟大的圣训学者`, yue: `偉大嘅聖訓學者`, ja: `偉大なるハディース学者たち`, ru: `Великие учёные хадиса`, es: `Los grandes sabios del hadiz`, ko: `위대한 하디스 학자들`, ta: `மகத்தான ஹதீஸ் அறிஞர்கள்`, si: `මහා හදීස් විද්වතුන්` },
  'scholars.1.note': { en: `The undisputed master of hadith criticism. He memorised 600,000 hadiths and could identify the weak narrators in each chain at sight. He reportedly prayed two rak'ahs before recording each hadith in the Sahih.`, ms: `Tokoh yang tidak dipertikaikan dalam kritik hadith. Beliau menghafal 600,000 hadith dan dapat mengenal pasti perawi yang lemah dalam setiap sanad dengan sekali pandang. Dilaporkan beliau bersolat dua rakaat sebelum merekodkan setiap hadith dalam Sahih.`, tur: `Hadis tenkidinin tartışmasız üstadı. 600.000 hadis ezberledi ve her zincirdeki zayıf râvîleri bir bakışta tespit edebiliyordu. Sahih'e her hadisi kaydetmeden önce iki rekât namaz kıldığı nakledilir.`, urd: `نقدِ حدیث کے بلا اختلاف امام۔ انہوں نے 600,000 احادیث یاد کیں اور ہر سند میں کمزور راویوں کو ایک نظر میں پہچان سکتے تھے۔ بیان کیا جاتا ہے کہ صحیح میں ہر حدیث درج کرنے سے پہلے وہ دو رکعت نماز پڑھتے تھے۔`, ben: `হাদিস সমালোচনার অবিসংবাদিত পুরোধা। তিনি ৬,০০,০০০ হাদিস মুখস্থ করেন এবং প্রতিটি সনদের দুর্বল বর্ণনাকারীদের এক নজরে চিনতে পারতেন। বর্ণিত আছে, সহিহে প্রতিটি হাদিস লিপিবদ্ধ করার আগে তিনি দুই রাকাত নামাজ পড়তেন।`, fas: `استاد بی‌چون‌وچرای نقد حدیث. او ۶۰۰٬۰۰۰ حدیث از بر داشت و می‌توانست راویان ضعیف هر سند را در یک نگاه بشناسد. گفته می‌شود پیش از ثبت هر حدیث در صحیح، دو رکعت نماز می‌گزارد.`, zh: `圣训批判无可争议的宗师。他熟记60万段圣训，能一望即识每条传述链中的弱传述者。据传他在《实录》中记录每段圣训前都礼两拜。`, yue: `聖訓批判無可爭議嘅宗師。佢熟記60萬段聖訓，能一望即識每條傳述鏈中嘅弱傳述者。據傳佢喺《實錄》中記錄每段聖訓前都禮兩拜。`, ja: `ハディース批判の議論の余地なき大家。60万のハディースを暗記し、各連鎖の弱い伝承者を一目で見抜くことができた。サヒーフに各ハディースを記録する前に二ラクアの礼拝をしたと伝えられる。`, ru: `Бесспорный мастер критики хадиса. Он выучил наизусть 600 000 хадисов и мог с первого взгляда определить слабых передатчиков в каждой цепи. Сообщается, что перед записью каждого хадиса в «Сахих» он совершал два ракаата молитвы.`, es: `El maestro indiscutible de la crítica del hadiz. Memorizó 600.000 hadices y podía identificar a primera vista a los narradores débiles de cada cadena. Se dice que rezaba dos rak'ahs antes de registrar cada hadiz en el Sahih.`, ko: `하디스 비평의 명실상부한 대가. 그는 60만 개의 하디스를 암기했으며 각 사슬의 약한 전승자를 한눈에 식별할 수 있었다. 그는 사히흐에 각 하디스를 기록하기 전에 두 라카의 예배를 드렸다고 전해진다.`, ta: `ஹதீஸ் விமர்சனத்தின் மறுக்கமுடியாத மேதை. அவர் 6,00,000 ஹதீஸ்களை மனனம் செய்து, ஒவ்வொரு சங்கிலியிலும் உள்ள பலவீன அறிவிப்பாளர்களை ஒரே பார்வையில் அடையாளம் காண முடிந்தது. ஸஹீஹில் ஒவ்வொரு ஹதீஸையும் பதிவுசெய்வதற்கு முன் அவர் இரண்டு ரக்அத் தொழுதார் எனக் கூறப்படுகிறது.`, si: `හදීස් විවේචනයේ අවිවාදිත ශූරයා. ඔහු හදීස් 600,000ක් කටපාඩම් කළ අතර, සෑම දාමයකම දුර්වල වාර්තාකරුවන් එක් බැල්මකින් හඳුනාගත හැකි විය. සහීහ්හි සෑම හදීසයක්ම සටහන් කිරීමට පෙර ඔහු රකආත් දෙකක් නැමඳ බව වාර්තා වේ.` },
  'scholars.2.note': { en: `Student of al-Bukhari. His arrangement of hadiths by topic, gathering all chains of a single hadith together, made his Sahih an unparalleled reference for legal scholars.`, ms: `Murid al-Bukhari. Susunan hadithnya mengikut topik, menghimpunkan semua sanad bagi satu hadith bersama-sama, menjadikan Sahihnya rujukan yang tiada tandingan bagi para ulama hukum.`, tur: `Buhârî'nin öğrencisi. Hadisleri konuya göre düzenlemesi, tek bir hadisin bütün isnadlarını bir araya getirmesi, Sahih'ini hukuk âlimleri için eşsiz bir başvuru kaynağı kıldı.`, urd: `امام بخاری کے شاگرد۔ ان کی احادیث کو موضوع کے اعتبار سے ترتیب دینا، ایک ہی حدیث کی تمام اسناد کو ایک ساتھ جمع کرنا، ان کی صحیح کو فقہاء کے لیے ایک بے مثال حوالہ بنا دیا۔`, ben: `ইমাম বুখারির ছাত্র। বিষয় অনুযায়ী হাদিস বিন্যাস, একটি হাদিসের সব সনদ একত্র করা, তাঁর সহিহকে আইনবিদদের জন্য অতুলনীয় তথ্যসূত্রে পরিণত করেছে।`, fas: `شاگرد بخاری. چینش احادیث بر اساس موضوع و گرد آوردن همه‌ی اسناد یک حدیث در کنار هم، صحیح او را مرجعی بی‌مانند برای فقها ساخت.`, zh: `布哈里的弟子。他按主题编排圣训、将一段圣训的所有传述链汇集一处，使其《实录》成为法律学者无可比拟的参考。`, yue: `布哈里嘅弟子。佢按主題編排聖訓、將一段聖訓嘅所有傳述鏈匯集一處，使其《實錄》成為法律學者無可比擬嘅參考。`, ja: `ブハーリーの弟子。ハディースを主題ごとに配列し、一つのハディースのすべての連鎖をまとめたことで、その『サヒーフ』は法学者にとって比類なき参照書となった。`, ru: `Ученик аль-Бухари. Его расположение хадисов по темам, объединение всех цепей одного хадиса вместе, сделало его «Сахих» непревзойдённым справочником для правоведов.`, es: `Discípulo de al-Bukhari. Su disposición de los hadices por temas, reuniendo todas las cadenas de un solo hadiz, hizo de su Sahih una referencia sin igual para los juristas.`, ko: `부카리의 제자. 주제별로 하디스를 배열하고 한 하디스의 모든 사슬을 함께 모은 그의 방식은 그의 사히흐를 법학자들에게 비할 데 없는 참고서로 만들었다.`, ta: `இமாம் புகாரியின் மாணவர். தலைப்பு வாரியாக ஹதீஸ்களை அமைத்து, ஒரே ஹதீஸின் அனைத்து சங்கிலிகளையும் ஒன்றாகத் தொகுத்தது, அவரது ஸஹீஹை சட்ட அறிஞர்களுக்கு ஈடிணையற்ற மேற்கோளாக்கியது.`, si: `බුහාරිගේ ශිෂ්‍යයා. මාතෘකාව අනුව හදීස් සැකසීම, එක් හදීසයක සියලු දාම එක්ව රැස් කිරීම, ඔහුගේ සහීහ් නීති විද්වතුන්ට අසමසම යොමුවක් බවට පත් කළේය.` },
  'scholars.3.note': { en: `Author of Fath al-Bari (the greatest commentary on Sahih al-Bukhari) and Tahdhib al-Tahdhib (biography of narrators). His expertise in rijal al-hadith is unsurpassed in the classical period.`, ms: `Pengarang Fath al-Bari (syarah terbesar bagi Sahih al-Bukhari) dan Tahdhib al-Tahdhib (biografi para perawi). Kepakarannya dalam rijal al-hadith tiada tandingan dalam zaman klasik.`, tur: `Fethu'l-Bârî'nin (Sahîh-i Buhârî'nin en büyük şerhi) ve Tehzîbü't-Tehzîb'in (râvîler biyografisi) yazarı. Ricâlü'l-hadîs alanındaki uzmanlığı klasik dönemde aşılmamıştır.`, urd: `فتح الباری (صحیح بخاری کی سب سے بڑی شرح) اور تہذیب التہذیب (راویوں کی سوانح) کے مصنف۔ رجال الحدیث میں ان کی مہارت کلاسیکی دور میں بے مثال ہے۔`, ben: `ফাতহুল বারি (সহিহ বুখারির সর্ববৃহৎ ব্যাখ্যাগ্রন্থ) ও তাহযিবুত তাহযিব (বর্ণনাকারীদের জীবনী)-এর রচয়িতা। রিজালুল হাদিসে তাঁর দক্ষতা ধ্রুপদি যুগে অতুলনীয়।`, fas: `نویسنده‌ی فتح الباری (بزرگ‌ترین شرح صحیح بخاری) و تهذیب التهذیب (زندگی‌نامه‌ی راویان). تخصص او در رجال الحدیث در دوران کلاسیک بی‌رقیب است.`, zh: `《法特赫·巴里》（《布哈里实录》最伟大的注释）与《塔赫济卜·塔赫济卜》（传述者传记）的作者。其在圣训传述者学（rijal al-hadith）方面的造诣，古典时期无人能及。`, yue: `《法特赫·巴里》（《布哈里實錄》最偉大嘅註釋）與《塔赫濟卜·塔赫濟卜》（傳述者傳記）嘅作者。其喺聖訓傳述者學（rijal al-hadith）方面嘅造詣，古典時期無人能及。`, ja: `『ファトフ・アル＝バーリー』（『サヒーフ・アル＝ブハーリー』の最大の注釈）と『タフズィーブ・アッ＝タフズィーブ』（伝承者の伝記）の著者。リジャール・アル＝ハディースにおける彼の専門性は、古典期において並ぶ者がない。`, ru: `Автор «Фатх аль-Бари» (величайшего комментария к «Сахиху» аль-Бухари) и «Тахзиб ат-Тахзиб» (биографий передатчиков). Его познания в риджаль аль-хадис не превзойдены в классический период.`, es: `Autor de Fath al-Bari (el mayor comentario al Sahih al-Bukhari) y Tahdhib al-Tahdhib (biografía de los narradores). Su pericia en rijal al-hadith no fue superada en el período clásico.`, ko: `파트흐 알바리(사히흐 알부카리에 대한 가장 위대한 주석)와 타흐디브 알타흐디브(전승자 전기)의 저자. 리잘 알하디스에 대한 그의 전문성은 고전기에 비할 데가 없다.`, ta: `ஃபத்ஹுல் பாரி (ஸஹீஹ் அல்-புகாரிக்கான மிகப் பெரிய விளக்கவுரை) மற்றும் தஹ்தீபுத் தஹ்தீப் (அறிவிப்பாளர்களின் வாழ்க்கை வரலாறு) ஆகியவற்றின் ஆசிரியர். ரிஜாலுல் ஹதீஸில் அவரது நிபுணத்துவம் செம்மொழிக் காலத்தில் ஈடிணையற்றது.`, si: `ෆත්හ් අල්-බාරි (සහීහ් අල්-බුහාරිගේ ශ්‍රේෂ්ඨතම විවරණය) සහ තහ්දීබ් අත්-තහ්දීබ් (වාර්තාකරුවන්ගේ චරිතාපදානය) කතුවරයා. රිජාල් අල්-හදීස් හි ඔහුගේ ප්‍රවීණත්වය සම්භාව්‍ය යුගයේ අභිබවා නැත.` },
  'scholars.4.note': { en: `The leading scholar of narrator critique (ilm al-jarh wa al-ta'dil) of his era. His assessments of narrators as 'trustworthy' (thiqa) or 'weak' (da'if) became authoritative reference points.`, ms: `Ulama terkemuka dalam kritik perawi (ilm al-jarh wa al-ta'dil) pada zamannya. Penilaiannya terhadap perawi sebagai 'boleh dipercayai' (thiqa) atau 'lemah' (da'if) menjadi rujukan yang berwibawa.`, tur: `Döneminin önde gelen râvî tenkidi (ilmü'l-cerh ve't-ta'dîl) âlimi. Râvîleri 'güvenilir' (sika) ya da 'zayıf' (zayıf) olarak değerlendirmesi, otoriter başvuru noktaları hâline geldi.`, urd: `اپنے دور میں نقدِ راوی (علم الجرح و التعدیل) کے سرکردہ عالم۔ راویوں کو 'ثقہ' یا 'ضعیف' قرار دینے کے ان کے فیصلے معتبر حوالے بن گئے۔`, ben: `তাঁর যুগে বর্ণনাকারী সমালোচনার (ইলমুল জারহ ওয়াত তাদিল) শীর্ষস্থানীয় আলেম। বর্ণনাকারীদের 'নির্ভরযোগ্য' (সিকাহ) বা 'দুর্বল' (যইফ) হিসেবে তাঁর মূল্যায়ন প্রামাণিক তথ্যসূত্রে পরিণত হয়।`, fas: `عالم برجسته‌ی نقد راوی (علم الجرح و التعدیل) در روزگار خود. ارزیابی‌های او از راویان به‌عنوان 'ثقه' یا 'ضعیف' به مرجع‌هایی معتبر بدل شد.`, zh: `其时代传述者评判（贬抑与采信之学）的首席学者。他将传述者评定为'可信'（西格）或'弱'（达伊夫）的判定，成为权威的参考。`, yue: `其時代傳述者評判（貶抑與採信之學）嘅首席學者。佢將傳述者評定為'可信'（西格）或'弱'（達伊夫）嘅判定，成為權威嘅參考。`, ja: `同時代における伝承者批判（ジャルフ・ワ・タアディール学）の第一人者。伝承者を「信頼できる」（シカ）または「弱い」（ダイーフ）と評価した彼の判断は、権威ある参照点となった。`, ru: `Ведущий учёный критики передатчиков (ильм аль-джарх ва-т-та'диль) своей эпохи. Его оценки передатчиков как «надёжных» (сика) или «слабых» (даиф) стали авторитетными ориентирами.`, es: `El principal sabio de la crítica de narradores (ilm al-jarh wa al-ta'dil) de su época. Sus evaluaciones de los narradores como 'fiables' (thiqa) o 'débiles' (da'if) se convirtieron en referencias autorizadas.`, ko: `그 시대 전승자 비평(일름 알자르흐 와 알타딜)의 선도적 학자. 전승자를 '신뢰할 만함'(시카) 또는 '약함'(다이프)으로 평가한 그의 판정은 권위 있는 기준점이 되었다.`, ta: `அவரது காலத்தில் அறிவிப்பாளர் விமர்சனத்தின் (இல்முல் ஜர்ஹ் வத் தஃதீல்) முன்னணி அறிஞர். அறிவிப்பாளர்களை 'நம்பகமான' (ஸிகா) அல்லது 'பலவீன' (ளயீஃப்) என அவர் மதிப்பிட்டது அதிகாரபூர்வமான மேற்கோள் புள்ளிகளாயின.`, si: `ඔහුගේ යුගයේ වාර්තාකරු විවේචනයේ (ඉල්ම් අල්-ජර්හ් වත්-තඃදීල්) ප්‍රමුඛ විද්වතා. වාර්තාකරුවන් 'විශ්වාසනීය' (සිකා) හෝ 'දුර්වල' (දයීෆ්) ලෙස ඔහුගේ තක්සේරු කිරීම් අධිකාරී යොමු ලක්ෂ්‍ය බවට පත් විය.` },
  'scholars.5.note': { en: `Author of Sharh Sahih Muslim, Riyad al-Salihin, al-Adhkar, and al-Arba'in al-Nawawiyyah. His commentary and collections remain primary references for students of hadith worldwide.`, ms: `Pengarang Sharh Sahih Muslim, Riyad al-Salihin, al-Adhkar, dan al-Arba'in al-Nawawiyyah. Syarah dan koleksinya kekal sebagai rujukan utama bagi pelajar hadith di seluruh dunia.`, tur: `Şerhu Sahîh-i Müslim, Riyâzü's-Sâlihîn, el-Ezkâr ve el-Erbaûne'n-Neveviyye'nin yazarı. Şerhi ve derlemeleri, dünya genelinde hadis talebeleri için birincil başvuru kaynağı olmayı sürdürür.`, urd: `شرح صحیح مسلم، ریاض الصالحین، الاذکار، اور الاربعین النوویہ کے مصنف۔ ان کی شرح اور مجموعے دنیا بھر میں طلبۂ حدیث کے لیے بنیادی حوالے ہیں۔`, ben: `শারহু সহিহ মুসলিম, রিয়াদুস সালিহিন, আল-আযকার, এবং আল-আরবাইন আন-নববিয়্যাহর রচয়িতা। তাঁর ব্যাখ্যা ও সংকলন বিশ্বজুড়ে হাদিস শিক্ষার্থীদের জন্য প্রাথমিক তথ্যসূত্র হয়ে আছে।`, fas: `نویسنده‌ی شرح صحیح مسلم، ریاض الصالحین، الاذکار و الاربعین النوویه. شرح و مجموعه‌های او همچنان مرجع اصلی دانشجویان حدیث در سراسر جهان است.`, zh: `《穆斯林实录注释》《善者乐园》《记主辞集》及《奈威四十圣训》的作者。其注释与辑录至今仍是全世界圣训学子的首要参考。`, yue: `《穆斯林實錄註釋》《善者樂園》《記主辭集》及《奈威四十聖訓》嘅作者。其註釋與輯錄至今仍係全世界聖訓學子嘅首要參考。`, ja: `『シャルフ・サヒーフ・ムスリム』『リヤード・アッ＝サーリヒーン』『アル＝アズカール』『アル＝アルバイーン・アン＝ナワウィーヤ』の著者。その注釈と集成は、世界中のハディース学徒にとって今なお第一級の参照である。`, ru: `Автор «Шарх Сахих Муслим», «Рийад ас-салихин», «Аль-Азкар» и «Аль-Арбаин ан-Нававийя». Его комментарий и сборники остаются основными справочниками для изучающих хадис по всему миру.`, es: `Autor de Sharh Sahih Muslim, Riyad al-Salihin, al-Adhkar y al-Arba'in al-Nawawiyyah. Su comentario y sus colecciones siguen siendo referencias primarias para los estudiantes del hadiz en todo el mundo.`, ko: `샤르흐 사히흐 무슬림, 리야드 알살리힌, 알아드카르, 알아르바인 알나와위야의 저자. 그의 주석과 모음집은 전 세계 하디스 학생들에게 여전히 일차적 참고서이다.`, ta: `ஷர்ஹு ஸஹீஹ் முஸ்லிம், ரியாளுஸ் ஸாலிஹீன், அல்-அத்கார், மற்றும் அல்-அர்பஈன் அந்-நவவிய்யா ஆகியவற்றின் ஆசிரியர். அவரது விளக்கவுரையும் தொகுப்புகளும் உலகெங்கிலும் உள்ள ஹதீஸ் மாணவர்களுக்கு முதன்மை மேற்கோள்களாக நீடிக்கின்றன.`, si: `ෂර්හ් සහීහ් මුස්ලිම්, රියාද් අස්-සාලිහීන්, අල්-අද්කාර්, සහ අල්-අර්බඊන් අන්-නවවිය්යා කතුවරයා. ඔහුගේ විවරණය සහ සංග්‍රහ ලොව පුරා හදීස් සිසුන්ට තවමත් ප්‍රාථමික යොමු ලෙස පවතී.` },
  'scholars.6.note': { en: `Author of Muqaddimah Ibn al-Salah (Ulum al-Hadith)  –  the foundational text in the science of hadith terminology. He codified the disciplines that every student of mustalah studies to this day.`, ms: `Pengarang Muqaddimah Ibn al-Salah (Ulum al-Hadith)  –  teks asas dalam ilmu istilah hadith. Beliau mengkanunkan disiplin-disiplin yang dipelajari oleh setiap pelajar mustalah hingga ke hari ini.`, tur: `Mukaddimetü İbnü's-Salâh'ın (Ulûmü'l-Hadîs) yazarı  –  hadis ıstılahı ilmindeki temel metin. Mustalah talebelerinin bugüne dek okuduğu disiplinleri o sistemleştirdi.`, urd: `مقدمہ ابن الصلاح (علوم الحدیث) کے مصنف  –  علم اصطلاح حدیث میں بنیادی متن۔ انہوں نے ان علوم کو مدوّن کیا جنہیں مصطلح کا ہر طالب علم آج تک پڑھتا ہے۔`, ben: `মুকাদ্দিমাহ ইবনুস সালাহ (উলুমুল হাদিস)-এর রচয়িতা  –  হাদিস পরিভাষা শাস্ত্রের ভিত্তিগ্রন্থ। তিনি সেই শাখাগুলোকে সংকলিত করেন যা মুসতালাহর প্রতিটি শিক্ষার্থী আজও অধ্যয়ন করে।`, fas: `نویسنده‌ی مقدمه‌ی ابن الصلاح (علوم الحدیث)  –  متن بنیادین در علم اصطلاح حدیث. او رشته‌هایی را مدوّن کرد که هر دانشجوی مصطلح تا امروز می‌آموزد.`, zh: `《伊本·萨拉赫导论》（《圣训学》）的作者  –  圣训术语学的奠基之作。他系统整理了至今每位术语学学子所修的各门学科。`, yue: `《伊本·薩拉赫導論》（《聖訓學》）嘅作者  –  聖訓術語學嘅奠基之作。佢系統整理咗至今每位術語學學子所修嘅各門學科。`, ja: `『ムカッディマ・イブン・アッ＝サラーフ』（『ウルーム・アル＝ハディース』）の著者  –  ハディース術語学の基礎的著作。彼は、ムスタラフの学徒が今日まで学ぶ諸学を体系化した。`, ru: `Автор «Мукаддима Ибн ас-Салах» («Улум аль-хадис»)  –  основополагающего труда в науке терминологии хадиса. Он систематизировал дисциплины, которые всякий изучающий мусталах постигает по сей день.`, es: `Autor de Muqaddimah Ibn al-Salah (Ulum al-Hadith)  –  el texto fundacional de la ciencia de la terminología del hadiz. Codificó las disciplinas que todo estudiante de mustalah estudia hasta hoy.`, ko: `무카디마 이븐 알살라흐(울룸 알하디스)의 저자  –  하디스 용어학의 기초 문헌. 그는 오늘날까지 모든 무스탈라흐 학생이 공부하는 학문 분과들을 체계화했다.`, ta: `முகத்திமா இப்னுஸ் ஸலாஹ் (உலூமுல் ஹதீஸ்)-இன் ஆசிரியர்  –  ஹதீஸ் கலைச்சொல் அறிவியலின் அடிப்படை நூல். முஸ்தலஹின் ஒவ்வொரு மாணவரும் இன்றுவரை பயிலும் துறைகளை அவர் தொகுத்தார்.`, si: `මුකද්දිමා ඉබ්නුස් සලාහ් (උලූම් අල්-හදීස්) කතුවරයා  –  හදීස් පාරිභාෂික විද්‍යාවේ මූලික ග්‍රන්ථය. මුස්තලහ් සෑම සිසුවෙකුම අද දක්වා හදාරන විෂයයන් ඔහු ක්‍රමවත් කළේය.` },

} satisfies Record<string, ML>;

